def _draw_lightning_bolt(painter: QPainter, size: int, color1: str, color2: str) -> None:
    """Draw a lightning bolt icon."""
    from PySide6.QtGui import QColor, QBrush
    
    painter.setPen(Qt.PenStyle.NoPen)
    gradient = QLinearGradient(0, 0, size, size)
    gradient.setColorAt(0, QColor(color1))
    gradient.setColorAt(1, QColor(color2))
    painter.setBrush(gradient)
    
    # Draw lightning bolt shape
    path = QPainterPath()
    path.moveTo(size/2, size/10)
    path.lineTo(size/3, size/2)
    path.lineTo(size/2 - 2, size/2)
    path.lineTo(size/3, size*0.9)
    path.lineTo(size*0.7, size/2 - 2)
    path.lineTo(size/2 + 2, size/2)
    path.closeSubpath()
    painter.drawPath(path)


def _draw_lightning_with_pins(painter: QPainter, size: int, color1: str, color2: str) -> None:
    """Draw a lightning bolt with circuit pins (for flashrom)."""
    from PySide6.QtGui import QColor, QPen
    
    # Draw lightning bolt
    _draw_lightning_bolt(painter, size, color1, color2)
    
    # Add circuit pins at bottom
    pen = QPen(QColor("#888888"), 1)
    painter.setPen(pen)
    pin_y = int(size * 0.85)
    for i in range(5):
        x = int(size * (0.2 + i * 0.15))
        painter.drawLine(x, pin_y, x, int(size * 0.98))


def _draw_lightning_with_controls(painter: QPainter, size: int, color1: str, color2: str) -> None:
    """Draw a lightning bolt with control dots (for flashprog - programmer)."""
    from PySide6.QtGui import QColor, QPen
    
    # Draw lightning bolt
    _draw_lightning_bolt(painter, size, color1, color2)
    
    # Add control dots on the right side
    painter.setPen(Qt.PenStyle.NoPen)
    painter.setBrush(QColor("#1A1A1A"))
    dot_x = int(size * 0.75)
    for i in range(3):
        y = int(size * (0.3 + i * 0.25))
        painter.drawEllipse(dot_x, y, int(size*0.12), int(size*0.12))


