def _draw_trash_bin(painter: QPainter, size: int, color1: str, color2: str) -> None:
    """Draw a detailed trash bin icon."""
    from PySide6.QtGui import QColor, QPen
    
    gradient = QLinearGradient(0, 0, size, size)
    gradient.setColorAt(0, QColor(color1))
    gradient.setColorAt(1, QColor(color2))
    
    # Handle (top)
    pen = QPen(gradient, 2)
    painter.setPen(pen)
    painter.setBrush(Qt.BrushStyle.NoBrush)
    painter.drawLine(int(size*0.35), int(size*0.08), int(size*0.65), int(size*0.08))
    painter.drawLine(int(size*0.35), int(size*0.08), int(size*0.38), int(size*0.15))
    painter.drawLine(int(size*0.65), int(size*0.08), int(size*0.62), int(size*0.15))
    
