def _draw_flashgui(painter: QPainter, size: int, color1: str, color2: str) -> None:
    """Draw the flashgui application icon — chip with lightning bolt on a dark rounded background."""
    from PySide6.QtGui import QColor, QPen

    painter.setPen(Qt.PenStyle.NoPen)

    # Dark rounded background
    bg = QLinearGradient(0, 0, size, size)
    bg.setColorAt(0, QColor("#0D1B2A"))
    bg.setColorAt(1, QColor("#1B3A5C"))
    painter.setBrush(bg)
    r = int(size * 0.18)
    painter.drawRoundedRect(0, 0, size, size, r, r)

    # Chip body
    chip_grad = QLinearGradient(0, 0, size, size)
    chip_grad.setColorAt(0, QColor(color1))
    chip_grad.setColorAt(1, QColor(color2))
    painter.setBrush(chip_grad)
    painter.drawRoundedRect(int(size * 0.25), int(size * 0.25),
                            int(size * 0.50), int(size * 0.50), 3, 3)

    # Chip pins — 3 per side (left & right)
    painter.setBrush(QColor("#90CAF9"))
    for i in range(3):
        y = int(size * (0.33 + i * 0.12))
        painter.drawRect(int(size * 0.12), y, int(size * 0.13), int(size * 0.07))  # left
        painter.drawRect(int(size * 0.75), y, int(size * 0.13), int(size * 0.07))  # right

    # Lightning bolt overlay (white, semi-transparent)
    painter.setBrush(QColor(255, 255, 255, 220))
    path = QPainterPath()
    path.moveTo(size * 0.54, size * 0.28)
    path.lineTo(size * 0.40, size * 0.52)
    path.lineTo(size * 0.50, size * 0.52)
    path.lineTo(size * 0.42, size * 0.72)
    path.lineTo(size * 0.62, size * 0.46)
    path.lineTo(size * 0.52, size * 0.46)
    path.closeSubpath()
    painter.drawPath(path)


def _settings_path() -> str:
    override = os.getenv("FLASHGUI_SETTINGS_PATH", "").strip()
    if override:
        return os.path.abspath(os.path.expanduser(override))
    return os.path.join(_app_config_dir(), SETTINGS_FILE)


def _legacy_settings_path() -> str:
    """Historical settings location (next to script/executable)."""
    if getattr(sys, "frozen", False):
        return os.path.join(os.path.dirname(os.path.abspath(sys.executable)), SETTINGS_FILE)
    return os.path.join(os.path.dirname(os.path.abspath(__file__)), SETTINGS_FILE)


def _app_config_dir() -> str:
    """Per-user writable config directory for persistent settings."""
    if sys.platform.startswith("win"):
        base = os.getenv("APPDATA") or os.path.expanduser("~")
        return os.path.join(base, "FlashGUI")
    if sys.platform == "darwin":
        return os.path.join(os.path.expanduser("~/Library/Application Support"), "flashgui")
    base = os.getenv("XDG_CONFIG_HOME") or os.path.expanduser("~/.config")
    return os.path.join(base, "flashgui")


def _default_workspace_dir() -> str:
    """Choose a sensible default workspace location."""
    if getattr(sys, "frozen", False):
        home = os.path.expanduser("~")
        if home and os.path.isdir(home):
            return home
        return os.getcwd()
    return os.path.dirname(os.path.abspath(__file__))


def _load_settings(path: str) -> dict[str, object]:
    try:
        with open(path, "r", encoding="utf-8") as f:
            obj = json.load(f)
        return obj if isinstance(obj, dict) else {}
    except (OSError, json.JSONDecodeError, UnicodeDecodeError):
        return {}


def _save_settings(path: str, data: dict[str, object]) -> None:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    fd = os.open(path, os.O_WRONLY | os.O_CREAT | os.O_TRUNC, 0o600)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
    except BaseException:
        try:
            os.close(fd)
        except OSError:
            pass
        raise


def _as_bool(value: object, default: bool = False) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        v = value.strip().lower()
        if v in {"1", "true", "yes", "on"}:
            return True
        if v in {"0", "false", "no", "off", ""}:
            return False
    if value is None:
        return default
    return bool(value)


def _register_proc(proc: subprocess.Popen) -> None:
    with _ACTIVE_PROCS_LOCK:
        _ACTIVE_PROCS.add(proc)


def _unregister_proc(proc: subprocess.Popen) -> None:
    with _ACTIVE_PROCS_LOCK:
        _ACTIVE_PROCS.discard(proc)


def _terminate_active_processes() -> None:
    with _ACTIVE_PROCS_LOCK:
        procs = list(_ACTIVE_PROCS)
    for proc in procs:
        try:
            if proc.poll() is None:
                proc.terminate()
                try:
                    proc.wait(timeout=1.5)
                except subprocess.TimeoutExpired:
                    proc.kill()
        except Exception:
            pass


def _active_operation_count() -> int:
    with _ACTIVE_PROCS_LOCK:
        return len(_ACTIVE_PROCS)


def _has_active_operations() -> bool:
    return _active_operation_count() > 0


def _ui_alive(root: object) -> bool:
    if _APP_SHUTTING_DOWN.is_set():
        return False
    if not _TK_AVAILABLE or tk is None:
        return False
    try:
        return bool(root.winfo_exists())  # type: ignore[union-attr]
    except Exception:
        return False


def _safe_after(root: object, delay_ms: int, callback: Callable[[], None]) -> None:
    if not _ui_alive(root):
        return
    try:
        root.after(delay_ms, callback)  # type: ignore[union-attr]
    except Exception:
        pass


def _set_preferred_mono_font(name: str) -> None:
    global _PREFERRED_MONO_FONT
    _PREFERRED_MONO_FONT = name.strip() or None


def _register_private_font_windows(font_path: str) -> bool:
    """Register font privately for the current process (Windows only)."""
    try:
        import ctypes

        FR_PRIVATE = 0x10
        added = ctypes.windll.gdi32.AddFontResourceExW(font_path, FR_PRIVATE, 0)
        return bool(added)
    except Exception:
        return False


def _font_cache_dir() -> str:
    if sys.platform.startswith("win"):
        base = os.getenv("LOCALAPPDATA") or os.path.expanduser("~")
    elif sys.platform == "darwin":
        base = os.path.join(os.path.expanduser("~"), "Library", "Caches")
    else:
        base = os.getenv("XDG_CACHE_HOME") or os.path.join(os.path.expanduser("~"), ".cache")
    p = os.path.join(base, "flashgui", "font-cache")
    os.makedirs(p, exist_ok=True)
    return p


def _font_download_cache_path(font_name: str) -> str | None:
    info = _FONT_DOWNLOADS.get(font_name)
    if not info:
        return None
    _url, filename = info
    return os.path.join(_font_cache_dir(), filename)


def _normalize_font_lookup_name(name: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", str(name or "").casefold())


def _match_downloadable_font_key(font_name: str) -> str | None:
    requested = (font_name or "").strip()
    if not requested:
        return None

    requested_casefold = requested.casefold()
    for key in _FONT_DOWNLOADS:
        if key.casefold() == requested_casefold:
            return key

    requested_norm = _normalize_font_lookup_name(requested)
    if not requested_norm:
        return None

    for key, (_url, filename) in _FONT_DOWNLOADS.items():
        key_norm = _normalize_font_lookup_name(key)
        file_norm = _normalize_font_lookup_name(os.path.splitext(filename)[0])
        if (
            requested_norm == key_norm
            or requested_norm == file_norm
            or requested_norm in file_norm
            or key_norm in requested_norm
        ):
            return key
    return None


def _preferred_font_storage_name(font_name: str) -> str:
    requested = (font_name or "").strip()
    return _match_downloadable_font_key(requested) or requested


def _resolve_downloadable_font_family(
    requested_font: str,
    register_font_file: Callable[[str], list[str]],
) -> str:
    requested = (requested_font or "").strip()
    if not requested:
        return ""

    requested_norm = _normalize_font_lookup_name(requested)
    candidate_keys: list[str] = []
    preferred_key = _match_downloadable_font_key(requested)
    if preferred_key:
        candidate_keys.append(preferred_key)
    candidate_keys.extend([key for key in _FONT_DOWNLOADS if key not in candidate_keys])

    for index, key in enumerate(candidate_keys):
        path = _font_download_cache_path(key)
        if index == 0 and preferred_key == key and (not path or not os.path.isfile(path)):
            try:
                path = _download_font(key)
            except Exception:
                path = None
        if not path or not os.path.isfile(path):
            continue

        families = [str(name).strip() for name in register_font_file(path) if str(name).strip()]
        if not families:
            continue
        if requested in families:
            return requested

        normalized_matches = [family for family in families if _normalize_font_lookup_name(family) == requested_norm]
        if normalized_matches:
            return normalized_matches[0]

        if preferred_key == key:
            return families[0]

    return requested


def _download_font(font_name: str) -> str | None:
    info = _FONT_DOWNLOADS.get(font_name)
    if not info:
        return None
    url, filename = info
    dst = os.path.join(_font_cache_dir(), filename)
    if os.path.isfile(dst) and os.path.getsize(dst) > 0:
        return dst

    candidates: list[str] = [url]
    if "github.com/" in url and "/raw/refs/heads/master/" in url:
        # Fallbacks in case upstream branch/path handling changes
        raw = (
            url.replace("https://github.com/", "https://raw.githubusercontent.com/")
            .replace("/raw/refs/heads/master/", "/HEAD/")
        )
        candidates.extend(
            [
                raw,
                raw.replace("/HEAD/", "/main/"),
                raw.replace("/HEAD/", "/master/"),
            ]
        )

    # Deduplicate while preserving order
    seen: set[str] = set()
    unique_candidates: list[str] = []
    for c in candidates:
        if c not in seen:
            seen.add(c)
            unique_candidates.append(c)

    last_error: Exception | None = None
    for candidate in unique_candidates:
        try:
            req = urllib.request.Request(candidate, headers={"User-Agent": "flashgui/1.0"})
            with urllib.request.urlopen(req, timeout=30) as resp, open(dst, "wb") as out:
                shutil.copyfileobj(resp, out)
            if os.path.isfile(dst) and os.path.getsize(dst) > 0:
                if not _validate_ttf_header(dst):
                    os.remove(dst)
                    continue
                return dst
        except Exception as exc:
            last_error = exc
            try:
                if os.path.isfile(dst):
                    os.remove(dst)
            except OSError:
                pass

    if last_error is not None:
        raise RuntimeError(f"Failed to download font '{font_name}' from all known URLs: {last_error}")
    return None


def _validate_ttf_header(path: str) -> bool:
    """Reject files that are not valid TrueType/OpenType fonts."""
    _VALID_SIGNATURES = (
        b"\x00\x01\x00\x00",  # TrueType
        b"OTTO",              # OpenType (CFF)
        b"true",              # Apple TrueType
        b"typ1",              # Apple Type 1
    )
    try:
        with open(path, "rb") as f:
            header = f.read(4)
        return any(header.startswith(sig) for sig in _VALID_SIGNATURES)
    except OSError:
        return False


def _ensure_font_available(font_name: str, logger: Callable[[str], None] | None = None) -> bool:
    if not font_name:
        return False
    if _TK_AVAILABLE and _tkfont is not None:
        try:
            if font_name in _tkfont.families():
                return True
        except Exception:
            pass
    if sys.platform.startswith("win"):
        try:
            path = _download_font(font_name)
            if not path:
                if logger:
                    logger(f"Font '{font_name}' is not installed and no download source is configured.")
                return False
            if _register_private_font_windows(path):
                if path not in _DOWNLOADED_FONT_PATHS:
                    _DOWNLOADED_FONT_PATHS.append(path)
                return True
            if logger:
                logger(f"Downloaded '{font_name}' but failed to register the font.")
            return False
        except Exception as exc:
            if logger:
                logger(f"Failed to download/register '{font_name}': {exc}")
            return False
    if logger:
        logger(
            f"Font '{font_name}' is not installed. Auto-download is currently supported on Windows only."
        )
    return False


def _install_embedded_font() -> None:
    """Decode/register embedded TTF payload when present."""
    global _EMBEDDED_FONT_PATH

    if (not _ALLOW_EMBEDDED_FONT_REDISTRIBUTION) or (not _EMBEDDED_TTF_B64.strip()) or _EMBEDDED_FONT_PATH:
        return

    try:
        raw = base64.b64decode(_EMBEDDED_TTF_B64, validate=True)
        fd, path = tempfile.mkstemp(prefix="flashgui_font_", suffix=".ttf")
        with os.fdopen(fd, "wb") as f:
            f.write(raw)
        _EMBEDDED_FONT_PATH = path

        if sys.platform.startswith("win"):
            _register_private_font_windows(path)

        def _cleanup() -> None:
            p = _EMBEDDED_FONT_PATH
            if not p:
                return
            try:
                if sys.platform.startswith("win"):
                    import ctypes

                    FR_PRIVATE = 0x10
                    ctypes.windll.gdi32.RemoveFontResourceExW(p, FR_PRIVATE, 0)
            except Exception:
                pass
            try:
                os.remove(p)
            except OSError:
                pass

        atexit.register(_cleanup)
    except (binascii.Error, OSError, ValueError):
        _EMBEDDED_FONT_PATH = None


def _cleanup_downloaded_fonts() -> None:
    if not sys.platform.startswith("win"):
        return
    try:
        import ctypes

        FR_PRIVATE = 0x10
        for p in _DOWNLOADED_FONT_PATHS:
            try:
                ctypes.windll.gdi32.RemoveFontResourceExW(p, FR_PRIVATE, 0)
            except Exception:
                pass
    except Exception:
        pass


atexit.register(_cleanup_downloaded_fonts)


def _pick_mono(size: int = 10) -> tuple[str, int]:
    """Return the best available monospace font tuple."""
    tk_families: set[str] = set()
    if _TK_AVAILABLE and _tkfont is not None:
        try:
            tk_families = set(_tkfont.families())
        except Exception:
            pass
    for name in (
        _PREFERRED_MONO_FONT,
        _EMBEDDED_FONT_NAME_HINT,
        "Consolas",
        "Lucida Console",
        "Courier New",
        "Courier",
    ):
        if name and (not tk_families or name in tk_families):
            return (name, size)
    return ("Courier", size)


