def _theme_is_dark(theme_name: str) -> bool:
    n = (theme_name or "").strip().lower()
    if n in _CUSTOM_DARK_THEMES:
        return True
    return any(k in n for k in ("dark", "black", "night", "midnight", "graphite", "macosx-dark"))

_FLASHROM_PROGRESS = re.compile(r"\[(READ|WRITE|ERASE):\s*(\d+)%\]", re.IGNORECASE)
_FLASHPROG_PROGRESS = re.compile(
    r"(Reading|Writing|Erasing|Progress)\.\.\.\s*\[[^\]]*\]\s*(\d+)%", re.IGNORECASE
)

# Programmer label hints captured from live USB detection.
# Key: exact programmer argument (e.g. "serprog:dev=/dev/ttyACM0")
# Value: human label (e.g. "EZP2020 serprog  [1a86:5722] → /dev/ttyACM0")
_PROGRAMMER_LABEL_HINTS: dict[str, str] = {}
_PROGRAMMER_BASE_LABEL_HINTS: dict[str, str] = {}
_MINIPRO_PROGRAMMER_ARG = "minipro-usb"


def _normalize_minipro_model_tokens(text: str) -> str:
    """Normalize common minipro model tokens to canonical casing."""
    if not text:
        return ""

    model_map = {
        "t48": "T48",
        "t56": "T56",
        "t76": "T76",
        "tl866": "TL866",
        "tl866ii+": "TL866II+",
        "tl866a/cs": "TL866A/CS",
    }

    return re.sub(
        r"\b(t48|t56|t76|tl866ii\+|tl866a/cs|tl866)\b",
        lambda m: model_map.get(m.group(1).lower(), m.group(1)),
        str(text),
        flags=re.IGNORECASE,
    )


def _programmer_friendly_name(prog: str) -> str:
    """Return a user-facing programmer name from live detection hints or static maps."""
    value = (prog or "").strip()
    if not value:
        return ""

    hinted = _PROGRAMMER_LABEL_HINTS.get(value, "").strip()
    if hinted:
        return _normalize_minipro_model_tokens(hinted.split("  [")[0].strip())

    base = value.split(":")[0].lower()
    if base in {"minipro-usb", "minipro"}:
        return "minipro USB programmer"
    base_hint = _PROGRAMMER_BASE_LABEL_HINTS.get(base, "").strip()
    if base_hint:
        return base_hint

    labels: list[str] = []
    seen: set[str] = set()
    for _, _, p, label in _USB_PROGRAMMER_MAP:
        if p.lower() == base and label not in seen:
            seen.add(label)
            labels.append(label)

    if len(labels) == 1:
        return labels[0]

    return base


def _format_programmer_status(prog: str) -> str:
    """Compose a status-string for the selected programmer."""
    value = (prog or "").strip()
    if not value:
        return " Programmer: — "
    friendly = _programmer_friendly_name(value)
    if friendly and friendly.lower() != value.lower():
        return f" Programmer: {friendly} ({value}) "
    return f" Programmer: {value} "

# ────────────────────────── tool discovery ─────────────────────────────────────

def _is_safe_binary_path(path: str) -> bool:
    """Reject binary paths that contain path-traversal or shell metacharacters."""
    if not path or not path.strip():
        return False
    normalized = os.path.normpath(path)
    if ".." in normalized.split(os.sep):
        return False
    _SHELL_META = set(";&|`$(){}")
    if any(ch in path for ch in _SHELL_META):
        return False
    return True


def _resolve_binary(name: str, env_var: str) -> str:
    override = os.getenv(env_var, "").strip()
    if override and _is_safe_binary_path(override):
        return override
    found = shutil.which(name)
    return found if found else name


def _get_version(binary: str) -> str | None:
    try:
        proc = subprocess.run(
            [binary, "--version"], check=False, capture_output=True, text=True, errors="replace", timeout=8
        )
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).strip().splitlines()
        return lines[0] if lines else None
    except Exception:
        return None


def _list_programmers(binary: str) -> list[str]:
    try:
        proc = subprocess.run([binary], check=False, capture_output=True, text=True, errors="replace", timeout=12)
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
        start = -1
        for i, line in enumerate(lines):
            if "programmer" in line.lower() and "supported" in line.lower():
                start = i + 1
                break
        if start == -1:
            return []
        programmers: list[str] = []
        seen: set[str] = set()
        for line in lines[start:]:
            clean = line.strip().replace(",", "").replace(".", "")
            if not clean:
                continue
            if clean.startswith("Please"):
                break
            for token in clean.split():
                if token and token[0].isalpha() and token.lower() not in {"and", "or"}:
                    if token not in seen:
                        programmers.append(token)
                        seen.add(token)
        return programmers
    except Exception:
        return []


def _is_minipro_tool(tool: str, binary: str = "") -> bool:
    t = (tool or "").strip().lower()
    if t == "minipro":
        return True
    b = os.path.basename((binary or "").strip()).lower()
    return b in {"minipro", "minipro.exe"}


def _detect_minipro_hardware(minipro_binary: str) -> tuple[bool, str, list[str]]:
    """Probe minipro hardware non-invasively and return (detected, label, output_lines).

    IMPORTANT: this intentionally avoids ``-t`` (self-test), because self-test can
    require the programmer to be disconnected from an inserted chip.

    ``minipro -V`` is preferred because it reports the connected programmer
    model (for example ``Found T48 ...``) without touching the target socket.
    A fallback to ``-l`` is kept for older builds that may not provide the same
    hardware summary on ``-V``.
    """
    def _run_probe(args: list[str]) -> tuple[list[str], str]:
        try:
            proc = subprocess.run(
                [minipro_binary, *args],
                check=False,
                capture_output=True,
                text=True,
                errors="replace",
                timeout=120,
            )
        except Exception:
            return [], ""

        out = ((proc.stdout or "") + "\n" + (proc.stderr or "")).strip()
        raw_lines = [ln.rstrip("\r\n") for ln in out.splitlines() if ln.strip()]
        found_line = ""
        for ln in raw_lines:
            if ln.lower().startswith("found "):
                found_line = _normalize_minipro_model_tokens(ln.strip())
                break
        diag_prefixes = (
            "found ",
            "warning:",
            "expected",
            "device code:",
            "serial code:",
            "manufactured:",
            "usb speed:",
            "supply voltage:",
        )
        lines = [
            _normalize_minipro_model_tokens(ln)
            for ln in raw_lines
            if ln.lower().startswith(diag_prefixes)
        ]
        if not lines:
            lines = [_normalize_minipro_model_tokens(ln) for ln in raw_lines[:20]]
        return lines, found_line

    lines, found_line = _run_probe(["-V"])
    if not found_line:
        fallback_lines, found_line = _run_probe(["-l"])
        if fallback_lines:
            lines = fallback_lines

    if not found_line:
        return False, "", lines

    label = found_line
    _PROGRAMMER_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = label
    model = ""
    model_match = re.search(r"\b(TL866II\+|TL866A/CS|TL866|T48|T56|T76)\b", label, re.IGNORECASE)
    if model_match:
        model = _normalize_minipro_model_tokens(model_match.group(1))
    _PROGRAMMER_BASE_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = f"minipro USB ({model})" if model else "minipro USB"
    return True, label, lines


def _list_minipro_devices(minipro_binary: str, limit: int = 8192) -> list[str]:
    """Return minipro part names from `minipro -l` output."""
    try:
        proc = subprocess.run(
            [minipro_binary, "-l"],
            check=False,
            capture_output=True,
            text=True,
            errors="replace",
            timeout=120,
        )
    except Exception:
        return []

    lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
    parts: list[str] = []
    seen: set[str] = set()
    skip_prefixes = (
        "minipro version",
        "usage:",
        "see the manual",
        "found ",
        "warning:",
        "device code:",
        "serial code:",
        "manufactured:",
        "usb speed:",
        "supply voltage:",
    )

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue
        if s.lower().startswith(skip_prefixes):
            continue
        token = s.split()[0].strip()
        if not token:
            continue
        if not re.fullmatch(r"[A-Za-z0-9@._()+\-/]+", token):
            continue
        k = token.lower()
        if k in seen:
            continue
        seen.add(k)
        parts.append(token)
        if len(parts) >= limit:
            break
    return parts


def _autodetect_minipro_spi_devices(minipro_binary: str) -> tuple[bool, str, list[str], list[str], str]:
    """Autodetect SPI 25xx devices using minipro ``-a``.

    Returns ``(detected_programmer, label, chips, lines, bus_width)`` where
    ``bus_width`` is either ``"8"`` / ``"16"`` when a match is found.
    """
    all_lines: list[str] = []
    found_line = ""

    def _collect_candidates(lines: list[str]) -> list[str]:
        chips: list[str] = []
        seen: set[str] = set()
        for raw in lines:
            s = (raw or "").strip()
            if not s:
                continue
            lo = s.lower()
            if (
                lo.startswith("found ")
                or lo.startswith("warning:")
                or lo.startswith("expected")
                or lo.startswith("device code:")
                or lo.startswith("serial code:")
                or lo.startswith("manufactured:")
                or lo.startswith("usb speed:")
                or lo.startswith("supply voltage:")
                or lo.startswith("autodetecting device")
                or lo.endswith("device(s) found.")
            ):
                continue
            if not re.fullmatch(r"[A-Za-z0-9@._()+\-/]+", s):
                continue
            k = s.lower()
            if k in seen:
                continue
            seen.add(k)
            chips.append(s)
        return chips

    for width in ("8", "16"):
        try:
            proc = subprocess.run(
                [minipro_binary, "-a", width],
                check=False,
                capture_output=True,
                text=True,
                errors="replace",
                timeout=60,
            )
        except Exception:
            continue

        raw_lines = [ln.rstrip("\r\n") for ln in ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines() if ln.strip()]
        norm_lines = [_normalize_minipro_model_tokens(ln) for ln in raw_lines]
        all_lines.extend(norm_lines)

        if not found_line:
            for ln in norm_lines:
                if ln.lower().startswith("found "):
                    found_line = ln.strip()
                    break

        chips = _collect_candidates(norm_lines)
        if chips:
            if found_line:
                _PROGRAMMER_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = found_line
                model = ""
                model_match = re.search(r"\b(TL866II\+|TL866A/CS|TL866|T48|T56|T76)\b", found_line, re.IGNORECASE)
                if model_match:
                    model = _normalize_minipro_model_tokens(model_match.group(1))
                _PROGRAMMER_BASE_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = f"minipro USB ({model})" if model else "minipro USB"
            return bool(found_line), found_line, chips, norm_lines[:120], width

    supported = _list_minipro_devices(minipro_binary)
    if supported:
        all_lines.append("No live SPI chip match from minipro -a 8/-a 16; listing supported minipro parts instead.")
        return bool(found_line), found_line, supported, all_lines[:120], ""

    return bool(found_line), found_line, [], all_lines[:120], ""


def _with_internal_programmer(programmers: list[str]) -> list[str]:
    """Return *programmers* with de-duplication and guaranteed 'internal'."""
    out: list[str] = []
    seen: set[str] = set()
    for p in programmers:
        s = (p or "").strip()
        if not s:
            continue
        k = s.lower()
        if k in seen:
            continue
        seen.add(k)
        out.append(s)
    if "internal" not in seen:
        out.append("internal")
    return out


# ── USB programmer detection ───────────────────────────────────────────────────

# FT232H SPI clock divisor — user-tunable via settings / env override.
# divisor=4 works for both 1.8 V and 3.3 V targets (safe default, slightly slower).
# divisor=2 is faster but only reliable on 3.3 V targets.
_FT232H_VALID_DIVISORS: tuple[str, ...] = ("2", "4")
_FT232H_DEFAULT_DIVISOR: str = "4"
_FT232H_DIVISOR: str = _FT232H_DEFAULT_DIVISOR


def _ft232h_programmer_arg(divisor: str | int | None = None) -> str:
    """Return the flashrom programmer arg for the FT232H using the given divisor."""
    raw = str(divisor if divisor is not None else _FT232H_DIVISOR).strip()
    if raw not in _FT232H_VALID_DIVISORS:
        raw = _FT232H_DEFAULT_DIVISOR
    return f"ft2232_spi:divisor={raw},type=232h"


def _normalize_ft232h_divisor(value: object) -> str:
    """Coerce arbitrary input to a supported FT232H divisor string."""
    raw = str(value if value is not None else "").strip()
    return raw if raw in _FT232H_VALID_DIVISORS else _FT232H_DEFAULT_DIVISOR


def _apply_ft232h_divisor(divisor: str | int | None) -> str:
    """Update the FT232H entry of _USB_PROGRAMMER_MAP in place and return the new arg."""
    global _FT232H_DIVISOR
    normalized = _normalize_ft232h_divisor(divisor)
    _FT232H_DIVISOR = normalized
    new_arg = _ft232h_programmer_arg(normalized)
    for idx, entry in enumerate(_USB_PROGRAMMER_MAP):
        vid, pid, _prog, label = entry
        if vid == "0403" and pid == "6014":
            _USB_PROGRAMMER_MAP[idx] = (vid, pid, new_arg, label)
            break
    return new_arg


