def _is_kde_desktop() -> bool:
    xdg = (os.environ.get("XDG_CURRENT_DESKTOP") or "").lower()
    sess = (os.environ.get("DESKTOP_SESSION") or "").lower()
    kde_flag = (os.environ.get("KDE_FULL_SESSION") or "").strip()
    return ("kde" in xdg) or ("plasma" in xdg) or ("kde" in sess) or (kde_flag not in {"", "0", "false", "False"})


def _preferred_keyring_manager_candidates() -> tuple[str, ...]:
    if _is_kde_desktop():
        return ("kwalletmanager5", "kwalletmanager", "seahorse")
    return ("seahorse", "kwalletmanager5", "kwalletmanager")


def _configured_udev_group() -> str:
    group = (os.environ.get("FLASHGUI_UDEV_GROUP") or "plugdev").strip()
    if not re.match(r"^[A-Za-z_][A-Za-z0-9_-]*$", group):
        return "plugdev"
    return group


def _apply_udev_group(rule_content: str) -> str:
    group = _configured_udev_group()
    return re.sub(r'GROUP="[^"]+"', f'GROUP="{group}"', rule_content)


def _udev_group_hint_text() -> str:
    group = _configured_udev_group()
    raw = (os.environ.get("FLASHGUI_UDEV_GROUP") or "").strip()
    if not raw:
        return f"Udev target group: {group} (default)"
    if group != raw:
        return f"Udev target group: {group} (invalid FLASHGUI_UDEV_GROUP={raw!r}; using default)"
    return f"Udev target group: {group} (from FLASHGUI_UDEV_GROUP)"


# Programmers that need a serial device path appended (programmer_arg → param key)
_SERIAL_PROGRAMMER_PARAMS: dict[str, str] = {
    "buspirate_spi": "dev",
    "serprog": "dev",
}


def _find_serial_port(label_hint: str = "") -> str | None:
    """Return the most likely ttyUSB/ttyACM device for a detected label hint."""
    hint = (label_hint or "").lower()
    preferred_tokens: list[str] = []
    if "ezp" in hint:
        preferred_tokens = ["ezp", "wch", "1a86", "ch340", "ch34"]
    elif "hydra" in hint:
        preferred_tokens = ["hydrabus", "1d50"]
    elif "bus pirate" in hint or "buspirate" in hint:
        preferred_tokens = ["buspirate", "bus_pirate", "dangerous", "0403"]

    try:
        by_id_dir = "/dev/serial/by-id"
        if preferred_tokens and os.path.isdir(by_id_dir):
            for name in sorted(os.listdir(by_id_dir)):
                lname = name.lower()
                if not any(tok in lname for tok in preferred_tokens):
                    continue
                full = os.path.join(by_id_dir, name)
                resolved = os.path.realpath(full)
                if os.path.exists(resolved) and os.path.basename(resolved).startswith(("ttyUSB", "ttyACM")):
                    return resolved

        ports = sorted(
            f"/dev/{n}" for n in os.listdir("/dev")
            if n.startswith(("ttyUSB", "ttyACM"))
        )
        return ports[0] if ports else None
    except OSError:
        return None


def _detect_programmer_serial_windows() -> list[tuple[str, str]]:
    """Detect likely serial-based programmers on Windows COM ports.

    Uses pyserial port metadata to map Hydrabus/Bus Pirate/serprog-style
    devices into flashrom programmer arguments like ``serprog:dev=COM7``.
    """
    results: list[tuple[str, str]] = []
    seen: set[str] = set()

    try:
        from serial.tools import list_ports  # type: ignore[import-not-found]
    except Exception:
        return results

    ports = list(list_ports.comports())
    for port in ports:
        device = str(getattr(port, "device", "")).strip()
        if not device:
            continue

        desc = str(getattr(port, "description", "")).strip()
        manu = str(getattr(port, "manufacturer", "")).strip()
        hwid = str(getattr(port, "hwid", "")).strip()
        blob = " ".join([device, desc, manu, hwid]).lower()

        prog = ""
        label = desc or manu or "Serial programmer"

        # Hydrabus / explicit serprog devices should use the serprog backend.
        if any(token in blob for token in ("hydrabus", "hydra bus", "serprog")):
            prog = f"serprog:dev={device}"
            label = desc or manu or "HydraBus / serprog"
        # Bus Pirate is typically exposed as a serial device too.
        elif any(token in blob for token in ("bus pirate", "buspirate")):
            prog = f"buspirate_spi:dev={device}"
            label = desc or manu or "Bus Pirate"

        if not prog or prog in seen:
            continue
        seen.add(prog)

        full_label = f"{label} → {device}"
        results.append((prog, full_label))
        _PROGRAMMER_LABEL_HINTS[prog] = full_label
        _PROGRAMMER_BASE_LABEL_HINTS[prog.split(":", 1)[0].lower()] = label

    # If nothing matched explicitly, still enumerate all COM ports so the
    # user can manually pick the right one (useful when the driver reports
    # only a generic USB Serial Device name).
    if not results:
        for port in ports:
            device = str(getattr(port, "device", "")).strip()
            if not device:
                continue
            desc = str(getattr(port, "description", "")).strip()
            manu = str(getattr(port, "manufacturer", "")).strip()
            label = desc or manu or device
            prog = f"serprog:dev={device}"
            if prog in seen:
                continue
            seen.add(prog)
            full_label = f"{label} → {device}"
            results.append((prog, full_label))
            _PROGRAMMER_LABEL_HINTS[prog] = full_label
            _PROGRAMMER_BASE_LABEL_HINTS["serprog"] = label

    return results


def _extract_windows_vid_pid_pairs(text: str) -> list[tuple[str, str]]:
    """Extract USB VID:PID pairs from Windows device listing output."""
    pairs: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for match in re.finditer(r"VID_([0-9A-Fa-f]{4})&PID_([0-9A-Fa-f]{4})", text or ""):
        pair = (match.group(1).lower(), match.group(2).lower())
        if pair in seen:
            continue
        seen.add(pair)
        pairs.append(pair)
    return pairs


def _enumerate_windows_usb_vid_pid_pairs() -> list[tuple[str, str]]:
    """Return connected Windows USB VID:PID pairs from built-in OS tooling."""
    collected: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()

    commands: list[list[str]] = [
        [
            "powershell",
            "-NoProfile",
            "-Command",
            "Get-CimInstance Win32_PnPEntity | Select-Object -ExpandProperty PNPDeviceID",
        ],
        [
            "powershell",
            "-NoProfile",
            "-Command",
            "Get-PnpDevice -PresentOnly | Select-Object -ExpandProperty InstanceId",
        ],
        ["pnputil", "/enum-devices", "/connected"],
    ]

    for cmd in commands:
        try:
            proc = subprocess.run(
                cmd,
                check=False,
                capture_output=True,
                text=True,
                errors="replace",
                timeout=12,
            )
        except Exception:
            continue

        pairs = _extract_windows_vid_pid_pairs((proc.stdout or "") + "\n" + (proc.stderr or ""))
        for pair in pairs:
            if pair in seen:
                continue
            seen.add(pair)
            collected.append(pair)

    return collected


def _detect_programmer_serial_posix() -> list[tuple[str, str]]:
    """Detect likely serial-based programmers on POSIX (especially macOS).

    On macOS, USB serial adapters are commonly exposed as ``/dev/cu.*``.
    We map known devices to flashrom programmer args and fall back to
    enumerating serial ports as ``serprog:dev=...`` when metadata is generic.
    """
    results: list[tuple[str, str]] = []
    seen: set[str] = set()

    try:
        from serial.tools import list_ports  # type: ignore[import-not-found]
    except Exception:
        return results

    ports = list(list_ports.comports())
    for port in ports:
        device = str(getattr(port, "device", "")).strip()
        if not device:
            continue

        desc = str(getattr(port, "description", "")).strip()
        manu = str(getattr(port, "manufacturer", "")).strip()
        hwid = str(getattr(port, "hwid", "")).strip()
        blob = " ".join([device, desc, manu, hwid]).lower()

        prog = ""
        label = desc or manu or "Serial programmer"

        if any(token in blob for token in ("hydrabus", "hydra bus", "serprog")):
            prog = f"serprog:dev={device}"
            label = desc or manu or "HydraBus / serprog"
        elif any(token in blob for token in ("bus pirate", "buspirate")):
            prog = f"buspirate_spi:dev={device}"
            label = desc or manu or "Bus Pirate"

        if not prog or prog in seen:
            continue
        seen.add(prog)

        full_label = f"{label} → {device}"
        results.append((prog, full_label))
        _PROGRAMMER_LABEL_HINTS[prog] = full_label
        _PROGRAMMER_BASE_LABEL_HINTS[prog.split(":", 1)[0].lower()] = label

    # On macOS many adapters are reported with generic names, so if no explicit
    # match was found, still expose serial ports as serprog candidates.
    if not results and sys.platform == "darwin":
        for port in ports:
            device = str(getattr(port, "device", "")).strip()
            if not device:
                continue
            if not (device.startswith("/dev/cu.") or device.startswith("/dev/tty.")):
                continue
            desc = str(getattr(port, "description", "")).strip()
            manu = str(getattr(port, "manufacturer", "")).strip()
            label = desc or manu or device
            prog = f"serprog:dev={device}"
            if prog in seen:
                continue
            seen.add(prog)
            full_label = f"{label} → {device}"
            results.append((prog, full_label))
            _PROGRAMMER_LABEL_HINTS[prog] = full_label
            _PROGRAMMER_BASE_LABEL_HINTS["serprog"] = label

    return results


def _programmer_display_label(prog: str) -> str:
    """Return a filename-safe display label for a programmer arg (e.g. 'ch341a_spi' -> 'CH341A')."""
    hinted = _PROGRAMMER_LABEL_HINTS.get(prog, "").strip()
    if hinted:
        return re.sub(r"[^A-Za-z0-9]", "", hinted.split()[0])

    base = prog.split(":")[0].lower()

    base_hint = _PROGRAMMER_BASE_LABEL_HINTS.get(base, "").strip()
    if base_hint:
        return re.sub(r"[^A-Za-z0-9]", "", base_hint.split()[0])

    # Reverse-look up against the USB map — take first word of the human label
    labels: list[str] = []
    seen: set[str] = set()
    for _, _, p, label in _USB_PROGRAMMER_MAP:
        if p.lower() == base and p not in seen:
            seen.add(p)
            labels.append(label)

    if len(labels) == 1:
        return re.sub(r"[^A-Za-z0-9]", "", labels[0].split()[0])

    # Ambiguous mapping (e.g. "serprog" can be HydraBus or EZP2020):
    # use neutral sanitized base instead of a possibly wrong hardware name.
    if len(labels) > 1:
        return re.sub(r"[^A-Za-z0-9]", "", base)

    # Fallback: sanitise the raw base
    return re.sub(r"[^A-Za-z0-9]", "", base)


def _build_rom_filename(workspace: str, chip: str, prog: str, tool: str = "") -> str:
    """Build an auto-generated ROM dump path.

    Format: <workspace>/<TOOL>_<Programmer>_<Chip>_<DDMMYYHHmm>.bin
    where TOOL is FR for flashrom and FP for flashprog.
    """
    chip_clean = re.sub(r"[^A-Za-z0-9]", "", chip)
    prog_label = _programmer_display_label(prog)
    tool_key = (tool or "").strip().lower()
    tool_prefix = (
        "FR" if tool_key == "flashrom" else
        "FP" if tool_key == "flashprog" else
        "MP" if tool_key == "minipro" else
        ""
    )
    dt = datetime.now().strftime("%d%m%y%H%M")
    core = f"{prog_label}_{chip_clean}_{dt}.bin"
    fname = f"{tool_prefix}_{core}" if tool_prefix else core
    return os.path.join(workspace or os.path.expanduser("~"), fname)


def _workspace_root() -> str:
    return os.path.dirname(os.path.dirname(os.path.abspath(__file__)))


def _resources_root() -> str:
    """Resolve the project resources directory with backward-compatible fallbacks."""
    script_dir = os.path.dirname(os.path.abspath(__file__))
    candidates = (
        os.path.join(script_dir, "resources"),
        os.path.join(_workspace_root(), "resources"),
        os.path.join(_workspace_root(), "flashgui", "resources"),
    )
    for p in candidates:
        if os.path.isdir(p):
            return p
    return candidates[0]


def _normalize_chip_key(text: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", (text or "").lower())


def _parse_int_literal(text: str, macros: dict[str, int]) -> int | None:
    token = (text or "").strip().rstrip(",")
    if not token:
        return None
    if token in macros:
        return macros[token]
    if re.fullmatch(r"0x[0-9a-fA-F]+", token):
        try:
            return int(token, 16)
        except ValueError:
            return None
    if re.fullmatch(r"\d+", token):
        try:
            return int(token, 10)
        except ValueError:
            return None
    return None


@lru_cache(maxsize=1)
def _load_chip_macros() -> dict[str, int]:
    macros: dict[str, int] = {}
    root = _workspace_root()
    for rel in (
        os.path.join("flashrom", "include", "flashchips.h"),
        os.path.join("flashprog", "include", "flashchips.h"),
    ):
        p = os.path.join(root, rel)
        if not os.path.isfile(p):
            continue
        try:
            with open(p, "r", encoding="utf-8", errors="replace") as f:
                for line in f:
                    m = re.match(r"^#define\s+([A-Z0-9_]+)\s+(0x[0-9A-Fa-f]+|\d+)", line)
                    if not m:
                        continue
                    name = m.group(1)
                    if name in macros:
                        continue
                    try:
                        macros[name] = int(m.group(2), 0)
                    except ValueError:
                        continue
        except OSError:
            continue
    return macros


@lru_cache(maxsize=1)
def _load_chip_registry() -> dict[tuple[int, int], list[dict[str, object]]]:
    """Build a lightweight chip registry from bundled flashrom/flashprog source trees."""
    registry: dict[tuple[int, int], list[dict[str, object]]] = {}
    macros = _load_chip_macros()
    root = _workspace_root()
    entry_re = re.compile(
        r'\{\s*\.vendor\s*=\s*"(?P<vendor>[^"]+)"\s*,.*?'
        r'\.name\s*=\s*"(?P<name>[^"]+)"\s*,.*?'
        r'\.manufacture_id\s*=\s*(?P<manuf>[A-Z0-9_]+)\s*,.*?'
        r'\.model_id\s*=\s*(?P<model>[A-Z0-9_]+)',
        re.S,
    )

    for tree in ("flashrom", "flashprog"):
        chips_dir = os.path.join(root, tree, "flashchips")
        if not os.path.isdir(chips_dir):
            continue
        for fname in sorted(os.listdir(chips_dir)):
            if not fname.endswith(".c"):
                continue
            path = os.path.join(chips_dir, fname)
            try:
                with open(path, "r", encoding="utf-8", errors="replace") as f:
                    content = f.read()
            except OSError:
                continue
            for m in entry_re.finditer(content):
                manuf = _parse_int_literal(m.group("manuf"), macros)
                model = _parse_int_literal(m.group("model"), macros)
                if manuf is None or model is None:
                    continue
                rec = {
                    "vendor": m.group("vendor"),
                    "name": m.group("name"),
                    "source": f"{tree}/flashchips/{fname}",
                }
                registry.setdefault((manuf, model), []).append(rec)

    for key, items in list(registry.items()):
        seen: set[tuple[str, str]] = set()
        deduped: list[dict[str, object]] = []
        for item in items:
            sig = (str(item.get("vendor", "")), str(item.get("name", "")))
            if sig in seen:
                continue
            seen.add(sig)
            deduped.append(item)
        registry[key] = deduped
    return registry


def _probe_id_key(manuf: int, model: int) -> str:
    return f"{manuf:x}:{model:x}"


def _datasheet_search_targets(chip_name: str) -> list[str]:
    """Build deterministic search URLs for datasheet discovery.

    User preference: keep fallback on AllDatasheet search only (no Google).
    """
    name = re.sub(r"\s+", " ", (chip_name or "").strip())
    if not name:
        return []
    name_q = quote_plus(name)
    return [f"https://www.alldatasheet.com/view.jsp?Searchword={name_q}"]


def _find_local_datasheet_pdf(local_pdf_root: str, *names: str) -> str | None:
    """Find a local datasheet PDF by case-insensitive and normalized-name matching."""
    if not os.path.isdir(local_pdf_root):
        return None

    try:
        entries = [n for n in os.listdir(local_pdf_root) if n.lower().endswith(".pdf")]
    except OSError:
        return None

    if not entries:
        return None

    by_lower_name: dict[str, str] = {}
    by_norm_stem: dict[str, str] = {}
    norm_entries: list[tuple[str, str]] = []

    for entry in entries:
        full = os.path.join(local_pdf_root, entry)
        lower = entry.lower()
        by_lower_name[lower] = full
        stem = os.path.splitext(entry)[0]
        norm = _normalize_chip_key(stem)
        if norm and norm not in by_norm_stem:
            by_norm_stem[norm] = full
        norm_entries.append((norm, full))

    for raw in names:
        if not raw:
            continue
        candidate = os.path.basename((raw or "").strip())
        if not candidate:
            continue

        # Direct, case-insensitive filename match.
        direct = by_lower_name.get(candidate.lower())
        if direct:
            return direct

        # If extension omitted in hint, try adding .pdf.
        if not candidate.lower().endswith(".pdf"):
            direct_pdf = by_lower_name.get((candidate + ".pdf").lower())
            if direct_pdf:
                return direct_pdf

        # Normalized stem match.
        stem = os.path.splitext(candidate)[0]
        norm = _normalize_chip_key(stem)
        if not norm:
            continue
        norm_hit = by_norm_stem.get(norm)
        if norm_hit:
            return norm_hit

        # Fuzzy fallback: substring match either way.
        for file_norm, full in norm_entries:
            if not file_norm:
                continue
            if norm in file_norm or file_norm in norm:
                return full

    return None


def _datasheet_query_candidates(chip: str, probe_ids: list[tuple[int, int]] | None = None) -> list[str]:
    """Build ordered candidate names for datasheet lookup/download."""
    ids = probe_ids or []
    hint_map = _load_datasheet_hint_map()
    registry = _load_chip_registry()

    out: list[str] = []
    seen: set[str] = set()

    def _add(name: str) -> None:
        n = (name or "").strip()
        if not n:
            return
        key = _normalize_chip_key(n)
        if not key or key in seen:
            return
        seen.add(key)
        out.append(n)

    _add(chip)

    for manuf, model in ids:
        hint = hint_map.get(_probe_id_key(manuf, model), {})
        if isinstance(hint, dict):
            _add(str(hint.get("preferred_name", "")))

        for rec in registry.get((manuf, model), []):
            _add(str(rec.get("name", "")))

    return out


def _extract_pdf_links_from_html(html: str, base_url: str) -> list[str]:
    """Extract likely PDF links from HTML content."""
    links: list[str] = []
    seen: set[str] = set()

    patterns = (
        re.compile(r'href=["\']([^"\']+\.pdf(?:\?[^"\']*)?)["\']', re.IGNORECASE),
        re.compile(r'href=["\']([^"\']*datasheet-pdf[^"\']*)["\']', re.IGNORECASE),
    )

    for pat in patterns:
        for m in pat.finditer(html):
            raw = (m.group(1) or "").strip()
            if not raw:
                continue
            full = urljoin(base_url, raw)
            if full in seen:
                continue
            seen.add(full)
            links.append(full)
    return links


def _download_pdf_to_local(url: str, local_pdf_root: str, name_hint: str) -> str | None:
    """Download a PDF URL to local datasheet cache and return saved path."""
    try:
        req = urllib.request.Request(
            url,
            headers={
                "User-Agent": "Mozilla/5.0 (FlashGUI Datasheet Fetcher)",
                "Accept": "application/pdf,text/html,*/*",
            },
        )
        with urllib.request.urlopen(req, timeout=12) as resp:
            payload = resp.read(16 * 1024 * 1024 + 1)
    except Exception:
        return None

    if not payload or len(payload) > 16 * 1024 * 1024:
        return None
    if not payload.startswith(b"%PDF"):
        return None

    parsed = urlparse(url)
    url_name = unquote(os.path.basename(parsed.path or "")).strip()
    if not url_name.lower().endswith(".pdf"):
        norm = _normalize_chip_key(name_hint).upper() or "DATASHEET"
        url_name = f"{norm}.pdf"

    # Keep a filesystem-safe name.
    safe_name = re.sub(r"[^A-Za-z0-9._-]", "_", url_name)
    if not safe_name.lower().endswith(".pdf"):
        safe_name += ".pdf"

    os.makedirs(local_pdf_root, exist_ok=True)
    dest = os.path.join(local_pdf_root, safe_name)

    # Avoid rewriting identical content.
    if os.path.isfile(dest):
        try:
            with open(dest, "rb") as f:
                if f.read() == payload:
                    return dest
        except OSError:
            pass

    try:
        with open(dest, "wb") as f:
            f.write(payload)
        return dest
    except OSError:
        return None


def _try_download_datasheet_pdf(chip: str, probe_ids: list[tuple[int, int]] | None = None) -> str | None:
    """Best-effort datasheet auto-download into local cache based on chip/probe IDs."""
    local_pdf_root = os.path.join(_resources_root(), "datasheets")
    query_names = _datasheet_query_candidates(chip, probe_ids)
    if not query_names:
        return None

    # If already present, return immediately.
    cached = _find_local_datasheet_pdf(local_pdf_root, *query_names)
    if cached:
        return cached

    # Query AllDatasheet pages and try first likely PDF links.
    for qname in query_names[:4]:
        search_targets = _datasheet_search_targets(qname)
        if not search_targets:
            continue
        search_url = search_targets[0]
        try:
            req = urllib.request.Request(
                search_url,
                headers={"User-Agent": "Mozilla/5.0 (FlashGUI Datasheet Fetcher)"},
            )
            with urllib.request.urlopen(req, timeout=12) as resp:
                html = resp.read(2 * 1024 * 1024).decode("utf-8", errors="replace")
        except Exception:
            continue

        for pdf_url in _extract_pdf_links_from_html(html, search_url)[:8]:
            saved = _download_pdf_to_local(pdf_url, local_pdf_root, qname)
            if saved:
                return saved
    return None


def _resolve_datasheet_target_for_open(chip: str, probe_ids: list[tuple[int, int]] | None = None) -> tuple[str | None, bool]:
    """Resolve target and auto-download PDF when possible.

    Returns (target, was_downloaded).
    """
    target = _chip_datasheet_target(chip, probe_ids)
    if not target:
        return None, False
    if os.path.isfile(target):
        return target, False

    downloaded = _try_download_datasheet_pdf(chip, probe_ids)
    if downloaded and os.path.isfile(downloaded):
        return downloaded, True
    return target, False


@lru_cache(maxsize=1)
def _load_datasheet_hint_map() -> dict[str, dict[str, str]]:
    """Load curated probe-id hints for canonical names and datasheet URLs."""
    path = os.path.join(_resources_root(), "chips", "datasheet_hint_map.json")
    if not os.path.isfile(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            raw = json.load(f)
    except Exception:
        return {}
    if not isinstance(raw, dict):
        return {}
    out: dict[str, dict[str, str]] = {}
    for k, v in raw.items():
        if not isinstance(k, str) or not isinstance(v, dict):
            continue
        rec: dict[str, str] = {}
        for field in ("vendor", "preferred_name", "datasheet_url", "datasheet_pdf_url", "local_pdf"):
            val = v.get(field)
            if isinstance(val, str) and val.strip():
                rec[field] = val.strip()
        if rec:
            out[k.lower()] = rec
    return out


@lru_cache(maxsize=1)
def _load_tested_chips() -> list[str]:
    """Load tested ROM chip list for Help/About display.

    Source file: resources/chips/tested_chips.json (JSON array of strings).
    Falls back to a curated built-in list if the file is missing/invalid.
    """
    path = os.path.join(_resources_root(), "chips", "tested_chips.json")
    if not os.path.isfile(path):
        return list(_DEFAULT_TESTED_CHIPS)
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            raw = json.load(f)
    except Exception:
        return list(_DEFAULT_TESTED_CHIPS)

    if not isinstance(raw, list):
        return list(_DEFAULT_TESTED_CHIPS)

    chips: list[str] = []
    seen: set[str] = set()
    for item in raw:
        if not isinstance(item, str):
            continue
        chip = item.strip()
        if not chip:
            continue
        key = chip.casefold()
        if key in seen:
            continue
        seen.add(key)
        chips.append(chip)

    return chips or list(_DEFAULT_TESTED_CHIPS)


def _resolve_chip_from_probe(chips: list[str], probe_ids: list[tuple[int, int]] | None) -> str | None:
    chips = [c.strip() for c in chips if c and c.strip()]
    if not chips:
        return None

    ids = probe_ids or []
    registry = _load_chip_registry()
    hint_map = _load_datasheet_hint_map()
    norm_chip_names = [_normalize_chip_key(c) for c in chips]

    for manuf, model in ids:
        hint = hint_map.get(_probe_id_key(manuf, model))
        preferred = (hint or {}).get("preferred_name", "").strip()
        if not preferred:
            continue
        pnorm = _normalize_chip_key(preferred)
        for chip, norm in zip(chips, norm_chip_names):
            if norm == pnorm or pnorm in norm or norm in pnorm:
                return chip

    for manuf, model in ids:
        candidates = registry.get((manuf, model), [])
        if not candidates:
            continue
        candidate_norms = {_normalize_chip_key(str(rec.get("name", ""))) for rec in candidates}
        for chip, norm in zip(chips, norm_chip_names):
            if norm in candidate_norms:
                return chip
        return str(candidates[0].get("name", chips[0]))

    return chips[0]


def _chip_datasheet_target(chip: str, probe_ids: list[tuple[int, int]] | None = None) -> str | None:
    chip = (chip or "").strip()
    if not chip:
        return None

    registry = _load_chip_registry()
    hint_map = _load_datasheet_hint_map()
    ids = probe_ids or []
    local_pdf_root = os.path.join(_resources_root(), "datasheets")
    resolved_name = ""
    fallback_url = ""

    def _is_pdf_url(url: str) -> bool:
        u = (url or "").strip().lower()
        return u.startswith(("http://", "https://")) and ".pdf" in u

    def _is_google_url(url: str) -> bool:
        u = (url or "").strip().lower()
        return "google." in u

    def _is_google_search_url(url: str) -> bool:
        u = (url or "").strip().lower()
        return "google." in u and "/search" in u

    for manuf, model in ids:
        hint = hint_map.get(_probe_id_key(manuf, model))
        if not hint:
            continue
        chipid_candidates = [
            f"{manuf:x}_{model:x}.pdf",
            f"{manuf:02x}_{model:04x}.pdf",
            f"{manuf:x}-{model:x}.pdf",
            f"{manuf:02x}-{model:04x}.pdf",
        ]
        for candidate in chipid_candidates:
            local_candidate = _find_local_datasheet_pdf(local_pdf_root, candidate)
            if local_candidate:
                return local_candidate
        preferred_name = hint.get("preferred_name", "").strip()
        local_pdf = hint.get("local_pdf", "").strip()
        local_candidate = _find_local_datasheet_pdf(local_pdf_root, local_pdf, preferred_name, chip)
        if local_candidate:
            return local_candidate
        if preferred_name and not resolved_name:
            resolved_name = preferred_name
        datasheet_pdf_url = hint.get("datasheet_pdf_url", "").strip()
        if _is_pdf_url(datasheet_pdf_url) and not _is_google_url(datasheet_pdf_url):
            return datasheet_pdf_url
        datasheet_url = hint.get("datasheet_url", "").strip()
        if _is_pdf_url(datasheet_url) and not _is_google_url(datasheet_url):
            return datasheet_url
        # Ignore legacy Google-search hints; prefer AllDatasheet fallback.
        if datasheet_url and not _is_google_url(datasheet_url) and not _is_google_search_url(datasheet_url) and not fallback_url:
            fallback_url = datasheet_url

    for manuf, model in ids:
        for rec in registry.get((manuf, model), []):
            name = str(rec.get("name", "")).strip()
            if not name:
                continue
            if not resolved_name:
                resolved_name = name
            local_candidate = _find_local_datasheet_pdf(local_pdf_root, name)
            if local_candidate:
                return local_candidate

    # Optional direct chip-id local naming even without hint map entries.
    for manuf, model in ids:
        for candidate in (
            f"{manuf:x}_{model:x}.pdf",
            f"{manuf:02x}_{model:04x}.pdf",
            f"{manuf:x}-{model:x}.pdf",
            f"{manuf:02x}-{model:04x}.pdf",
        ):
            local_candidate = _find_local_datasheet_pdf(local_pdf_root, candidate)
            if local_candidate:
                return local_candidate

    # Final local fallback from current chip text before web search.
    local_candidate = _find_local_datasheet_pdf(local_pdf_root, chip, resolved_name)
    if local_candidate:
        return local_candidate

    if fallback_url:
        return fallback_url

    targets = _datasheet_search_targets(resolved_name or chip)
    if targets:
        return targets[0]
    return None


def _open_datasheet_target(target: str) -> None:
    if not target:
        return
    if os.path.isfile(target):
        try:
            if sys.platform == "darwin":
                subprocess.Popen(["open", target])
            elif sys.platform.startswith("linux"):
                subprocess.Popen(["xdg-open", target])
            else:
                os.startfile(target)  # type: ignore[attr-defined]
        except Exception:
            normalized = target.replace("\\", "/")
            webbrowser.open(f"file:///{normalized}")
        return
    webbrowser.open(target)


def _detect_programmer_usb() -> list[tuple[str, str]]:
    """Scan lsusb for known flash programmers.

    Returns a list of (programmer_arg, description) tuples in discovery order.
    Duplicate programmer_args are suppressed (first match wins).
    """
    if sys.platform.startswith("win"):
        # On Windows, merge USB VID:PID detection with serial-port metadata.
        _PROGRAMMER_LABEL_HINTS.clear()
        _PROGRAMMER_BASE_LABEL_HINTS.clear()
        results: list[tuple[str, str]] = []
        seen: set[str] = set()

        for vid, pid in _enumerate_windows_usb_vid_pid_pairs():
            for (v, p, prog, label) in _USB_PROGRAMMER_MAP:
                if v != vid or p != pid:
                    continue
                if prog in _SERIAL_PROGRAMMER_PARAMS:
                    # Serial backends on Windows should be exposed with explicit COM paths.
                    break
                if prog in seen:
                    break
                full_label = f"{label}  [{vid}:{pid}]"
                results.append((prog, full_label))
                _PROGRAMMER_LABEL_HINTS[prog] = full_label
                _PROGRAMMER_BASE_LABEL_HINTS[prog] = label
                seen.add(prog)
                break

        for prog, label in _detect_programmer_serial_windows():
            if prog in seen:
                continue
            results.append((prog, label))
            seen.add(prog)

        return results
    if sys.platform == "darwin":
        # On macOS, lsusb may be unavailable; rely on serial metadata.
        return _detect_programmer_serial_posix()

    results: list[tuple[str, str]] = []
    seen: set[str] = set()
    used_serial_ports: set[str] = set()

    def _add_detected(prog: str, label: str, vid: str = "", pid: str = "") -> None:
        if not prog or prog in seen:
            return
        if prog in _SERIAL_PROGRAMMER_PARAMS:
            key = _SERIAL_PROGRAMMER_PARAMS[prog]
            port = _find_serial_port(label)
            if port:
                # Avoid ambiguous false positives from fallback dmesg heuristics:
                # once a serial port is claimed by a detected programmer, do not
                # map the same /dev/tty* to a different programmer candidate.
                if port in used_serial_ports:
                    return
                full_prog = f"{prog}:{key}={port}"
                suffix = f"  [{vid}:{pid}]" if vid and pid else ""
                full_label = f"{label}{suffix} → {port}"
                results.append((full_prog, full_label))
                _PROGRAMMER_LABEL_HINTS[full_prog] = full_label
                used_serial_ports.add(port)
            else:
                # Do not advertise serial programmers without a usable device
                # path (prevents false positives such as bare "serprog").
                return
            _PROGRAMMER_BASE_LABEL_HINTS[prog] = label
            seen.add(prog)
            return

        suffix = f"  [{vid}:{pid}]" if vid and pid else ""
        full_label = f"{label}{suffix}"
        results.append((prog, full_label))
        _PROGRAMMER_LABEL_HINTS[prog] = full_label
        _PROGRAMMER_BASE_LABEL_HINTS[prog] = label
        seen.add(prog)

    try:
        # Reset stale hints each scan so UI labels always reflect current evidence.
        _PROGRAMMER_LABEL_HINTS.clear()
        _PROGRAMMER_BASE_LABEL_HINTS.clear()

        proc = subprocess.run(
            ["lsusb"], check=False, capture_output=True, text=True, errors="replace", timeout=6
        )
        for line in (proc.stdout or "").splitlines():
            m = re.search(r"ID\s+([0-9a-fA-F]{4}):([0-9a-fA-F]{4})", line)
            if not m:
                continue
            vid, pid = m.group(1).lower(), m.group(2).lower()
            lo = line.lower()
            for (v, p, prog, label) in _USB_PROGRAMMER_MAP:
                if v == vid and p == pid:
                    resolved_label = label
                    if label.lower().startswith("bus pirate") and "v3" in lo:
                        resolved_label = "Bus Pirate v3"
                    _add_detected(prog, resolved_label, vid=vid, pid=pid)
                    break

        # Fallback/augment with recent kernel messages on Linux.
        # This is especially useful when lsusb is unavailable or too generic.
        if sys.platform.startswith("linux"):
            dmesg_output = ""
            for cmd in (["dmesg", "--color=never", "-T"], ["dmesg"]):
                try:
                    dp = subprocess.run(
                        cmd, check=False, capture_output=True, text=True, errors="replace", timeout=6
                    )
                except (FileNotFoundError, OSError):
                    continue
                dmesg_output = dp.stdout or ""
                if dmesg_output.strip():
                    break

            if dmesg_output.strip():
                # Prefer newest evidence by scanning from bottom to top.
                for line in reversed(dmesg_output.splitlines()[-600:]):
                    lo = line.lower()
                    for key, prog, label in _DMESG_PROGRAMMER_MAP:
                        if key in lo:
                            resolved_label = label
                            if label.lower().startswith("bus pirate") and "v3" in lo:
                                resolved_label = "Bus Pirate v3"
                            _add_detected(prog, resolved_label)
                            break
    except (FileNotFoundError, OSError):
        pass

    return results


def _detect_chips(
    binary: str,
    programmer: str,
    out_queue: queue.Queue[str] | None = None,
    *,
    use_sudo: bool = False,
    sudo_password: str = "",
) -> tuple[list[str], str | None, list[tuple[int, int]], str | None]:
    """Probe for chips.

    Returns (chips, suggested_programmer_or_None, probe_ids, failure_hint_or_None).
    """

    def _probe_failure_hint(text: str, prog: str, rc: int) -> str | None:
        lo = (text or "").lower()
        is_internal = (prog or "").strip().startswith("internal")
        privilege_markers = (
            "could not get i/o privileges",
            "operation not permitted",
            "permission denied",
            "requires root",
            "run as root",
            "raw access permission",
            "programmer initialization failed",
            "cannot map ecam region",
        )
        if is_internal and any(m in lo for m in privilege_markers):
            return (
                "Internal programmer likely needs elevation/root privileges. "
                "Run the GUI (or command) with sudo/root and retry."
            )
        if rc != 0 and not text.strip():
            return f"Chip probe failed (exit {rc}) with no output."
        return None

    def _extract_probe_ids(lines: list[str]) -> list[tuple[int, int]]:
        ids: list[tuple[int, int]] = []
        seen: set[tuple[int, int]] = set()
        patterns = (
            r"compare_id:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"(?:probe_spi_rdid|spi_rdid)\s*:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"\bid1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
        )
        for line in lines:
            for pat in patterns:
                m_id = re.search(pat, line, re.IGNORECASE)
                if not m_id:
                    continue
                try:
                    pair = (int(m_id.group(1), 16), int(m_id.group(2), 16))
                except ValueError:
                    continue
                if pair in seen:
                    continue
                seen.add(pair)
                ids.append(pair)
        return ids

    base_cmd = [binary, "-V", "-p", programmer]
    cmd = list(base_cmd)
    stdin_text: str | None = None

    is_linux = sys.platform.startswith("linux")
    is_internal = (programmer or "").strip().startswith("internal")
    if use_sudo and is_linux and is_internal:
        if sudo_password:
            # Non-interactive password feed via stdin; avoid terminal prompts.
            cmd = ["sudo", "-S", "-p", ""] + base_cmd
            stdin_text = sudo_password + "\n"
        else:
            # Try cached credentials without prompting.
            cmd = ["sudo", "-n"] + base_cmd

    if out_queue is not None:
        out_queue.put(f"$ {' '.join(cmd)}")
    try:
        proc = subprocess.run(
            cmd,
            input=stdin_text,
            check=False,
            capture_output=True,
            text=True,
            errors="replace",
            timeout=30,
        )
        rc = int(proc.returncode)
        combined = (proc.stdout or "") + "\n" + (proc.stderr or "")
        if out_queue is not None:
            for ln in combined.splitlines():
                out_queue.put(ln)
        chips: list[str] = []
        seen: set[str] = set()
        suggested: str | None = None
        lines = combined.splitlines()
        probe_ids = _extract_probe_ids(lines)
        for line in lines:
            lo = line.lower()
            # "Found GigaDevice flash chip \"GD25Q32(B)\" ..."
            # "Multiple flash chip definitions match ... \"A\", \"B\""
            if "found" in lo or "multiple" in lo or "match" in lo:
                for m in re.finditer(r'"([^"]+)"|\'([^\']+)\'', line):
                    name = m.group(1) or m.group(2)
                    if name not in seen:
                        chips.append(name)
                        seen.add(name)
            # flashrom hint: "Use flashrom -p buspirate_spi:dev=/dev/ttyUSB0"
            if not suggested:
                hint = re.search(r'Use \S+ -p (\S+)', line)
                if hint:
                    suggested = hint.group(1)
        return chips, suggested, probe_ids, _probe_failure_hint(combined, programmer, rc)
    except Exception:
        return [], None, [], "Chip probe failed due to an unexpected runtime error."


def _extract_programmer_from_cmd(cmd: list[str]) -> str:
    """Best-effort extraction of programmer arg from a flashrom/flashprog command."""
    for i, tok in enumerate(cmd):
        if tok in ("-p", "--programmer") and i + 1 < len(cmd):
            return str(cmd[i + 1]).strip()
    return ""


def _with_optional_sudo_for_internal(
    cmd: list[str],
    *,
    use_sudo: bool = False,
    sudo_password: str = "",
) -> tuple[list[str], str | None]:
    """Wrap command with sudo for Linux internal programmer operations.

    Returns (final_cmd, stdin_text_or_None).
    """
    final_cmd = list(cmd)
    stdin_text: str | None = None
    if not (use_sudo and sys.platform.startswith("linux")):
        return final_cmd, stdin_text

    prog = _extract_programmer_from_cmd(cmd)
    if not prog.startswith("internal"):
        return final_cmd, stdin_text

    if sudo_password:
        final_cmd = ["sudo", "-S", "-p", ""] + final_cmd
        stdin_text = sudo_password + "\n"
    else:
        final_cmd = ["sudo", "-n"] + final_cmd
    return final_cmd, stdin_text


def _get_chip_size(binary: str, programmer: str, chip: str) -> int | None:
    try:
        proc = subprocess.run(
            [binary, "-p", programmer, "-c", chip, "--flash-size"],
            check=False, capture_output=True, text=True, errors="replace", timeout=15
        )
        lines = ((proc.stdout or "") + "\n" + (proc.stderr or "")).splitlines()
        # The size is a bare integer line; scan in reverse to skip trailing messages
        for line in reversed(lines):
            stripped = line.strip()
            if re.fullmatch(r"\d+", stripped):
                return int(stripped)
        return None
    except Exception:
        return None


def _run_command(
    cmd: list[str],
    out_queue: queue.Queue[str],
    *,
    use_sudo: bool = False,
    sudo_password: str = "",
    echo_command: bool = True,
) -> int:
    """Run *cmd*, echo its command line, stream output to *out_queue*. Returns exit code."""
    run_cmd, stdin_text = _with_optional_sudo_for_internal(
        cmd, use_sudo=use_sudo, sudo_password=sudo_password
    )
    if echo_command:
        out_queue.put(f"$ {' '.join(run_cmd)}")
    try:
        proc = subprocess.Popen(
            run_cmd,
            stdin=subprocess.PIPE if stdin_text is not None else None,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            text=True, universal_newlines=True, errors="replace",
        )
        _register_proc(proc)
        if stdin_text is not None and proc.stdin is not None:
            try:
                proc.stdin.write(stdin_text)
                proc.stdin.flush()
            finally:
                try:
                    proc.stdin.close()
                except Exception:
                    pass
        if proc.stdout is None:
            out_queue.put("ERROR: Failed to capture command output stream.")
            return 1
        for line in proc.stdout:
            if _APP_SHUTTING_DOWN.is_set() and proc.poll() is None:
                proc.terminate()
                break
            out_queue.put(line.rstrip("\n"))
        proc.wait()
        return proc.returncode
    except (FileNotFoundError, OSError, ValueError) as exc:
        out_queue.put(f"ERROR: {exc}")
        return 1
    finally:
        try:
            _unregister_proc(proc)  # type: ignore[name-defined]
        except Exception:
            pass


def _run_command_progress(
    cmd: list[str],
    out_queue: queue.Queue[str],
    pct_callback: Callable[[int], None] | None = None,
    *,
    use_sudo: bool = False,
    sudo_password: str = "",
    echo_command: bool = True,
) -> int:
    """Like *_run_command* but parses real-time progress from stdout.

    Splits the process into two threads: stderr → log queue (line-based),
    stdout → char-by-char with backspace handling → log queue + *pct_callback*.
    Returns the exit code.
    """
    _pct_re = re.compile(r"(\d{1,3})\s*%")
    _done_re = re.compile(
        r"(erase/write done|erase done|write done|verified|verification.*(?:ok|success)|read:\s*100%)",
        re.IGNORECASE,
    )
    _ansi_re = re.compile(r"\x1b\[[0-?]*[ -/]*[@-~]")
    _minipro_prog_re = re.compile(r"^(Reading|Writing|Erasing|Verifying)\b.*?(\d{1,3})%$", re.IGNORECASE)

    is_minipro_cmd = bool(cmd) and os.path.basename(str(cmd[0]).strip()).lower() in {"minipro", "minipro.exe"}

    pct_state = {"last": -1}
    pct_lock = threading.Lock()
    minipro_state = {
        "last_pct": -1,
        "last_line": "",
    }

    def _clean_line(raw: str) -> str:
        s = _ansi_re.sub("", str(raw or ""))
        s = s.replace("\r", "")
        return s.strip()

    def _emit_pct(value: int) -> None:
        if pct_callback is None:
            return
        pct = max(0, min(100, int(value)))
        with pct_lock:
            if pct <= pct_state["last"]:
                return
            pct_state["last"] = pct
        pct_callback(pct)

    def _emit_line(line: str) -> None:
        cleaned = _clean_line(line)
        if not cleaned:
            return

        if is_minipro_cmd:
            m_prog = _minipro_prog_re.match(cleaned)
            if m_prog:
                pct = max(0, min(100, int(m_prog.group(2))))
                _emit_pct(pct)
                if pct == minipro_state["last_pct"]:
                    return
                minipro_state["last_pct"] = pct
                verb = m_prog.group(1).capitalize()
                cleaned = f"{verb}... {pct}%"

            if cleaned == minipro_state["last_line"]:
                return
            minipro_state["last_line"] = cleaned

        out_queue.put(cleaned)

        m = _pct_re.search(cleaned)
        if m:
            _emit_pct(int(m.group(1)))
        elif _done_re.search(cleaned):
            _emit_pct(100)
    run_cmd, stdin_text = _with_optional_sudo_for_internal(
        cmd, use_sudo=use_sudo, sudo_password=sudo_password
    )
    if echo_command:
        out_queue.put(f"$ {' '.join(run_cmd)}")
    try:
        proc = subprocess.Popen(
            run_cmd,
            stdin=subprocess.PIPE if stdin_text is not None else None,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            universal_newlines=True,
            errors="replace",
            bufsize=1,
        )
        _register_proc(proc)
        if stdin_text is not None and proc.stdin is not None:
            try:
                proc.stdin.write(stdin_text)
                proc.stdin.flush()
            finally:
                try:
                    proc.stdin.close()
                except Exception:
                    pass
        if proc.stdout is None or proc.stderr is None:
            out_queue.put("ERROR: Failed to capture command output streams.")
            return 1

        def _read_log(stream: object) -> None:
            for raw in stream:  # type: ignore[union-attr]
                _emit_line(str(raw).rstrip("\n"))

        def _read_progress(stream: object) -> None:
            buf = ""
            while True:
                ch = stream.read(1)  # type: ignore[union-attr]
                if not ch:
                    break
                if ch == "\b":
                    if buf:
                        buf = buf[:-1]
                elif ch == "\n":
                    _emit_line(buf)
                    buf = ""
                else:
                    buf += ch
                    m = _pct_re.search(buf)
                    if m:
                        _emit_pct(int(m.group(1)))
                if len(buf) > 500:
                    buf = buf[-100:]

            tail = buf.strip()
            if tail:
                _emit_line(tail)

        t_out = threading.Thread(target=_read_progress, args=(proc.stdout,), daemon=True)
        t_err = threading.Thread(target=_read_log,      args=(proc.stderr,), daemon=True)
        t_out.start(); t_err.start()
        started = time.monotonic()
        while t_out.is_alive() or t_err.is_alive():
            t_out.join(timeout=0.1)
            t_err.join(timeout=0.1)
            if _APP_SHUTTING_DOWN.is_set() and proc.poll() is None:
                proc.terminate()
            if time.monotonic() - started > _COMMAND_TIMEOUT_SEC:
                out_queue.put(f"ERROR: Command timed out after {_COMMAND_TIMEOUT_SEC}s")
                if proc.poll() is None:
                    proc.terminate()
                break
        return proc.wait()
    except (FileNotFoundError, OSError, ValueError) as exc:
        out_queue.put(f"ERROR: {exc}")
        return 1
    finally:
        try:
            _unregister_proc(proc)  # type: ignore[name-defined]
        except Exception:
            pass


# ────────────────────────── helpers ────────────────────────────────────────────

def _pad_file(src: str, target_size: int, tmpdir: str) -> str:
    """Copy *src* to a temp file and pad to *target_size* with 0xFF. Return new path."""
    dst = os.path.join(tmpdir, "padded_" + os.path.basename(src))
    shutil.copy2(src, dst)
    current = os.path.getsize(dst)
    if current < target_size:
        with open(dst, "ab") as f:
            f.write(b"\xff" * (target_size - current))
    return dst


def _remove_padding(path: str) -> int:
    """Truncate trailing 0xFF bytes from *path*. Return number of bytes removed."""
    with open(path, "rb") as f:
        data = f.read()
    stripped = data.rstrip(b"\xff")
    removed = len(data) - len(stripped)
    if removed:
        with open(path, "wb") as f:
            f.write(stripped)
    return removed


def _extract_chip_id_from_lines(lines: list[str]) -> str:
    """Extract chip ID text from minipro/flashrom-style probe output lines."""
    found_ids: list[str] = []
    seen: set[str] = set()

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue

        m_chip = re.search(r"\bchip\s*id\s*:\s*(0x[0-9a-fA-F]+)", s, re.IGNORECASE)
        if m_chip:
            chip_id = m_chip.group(1).upper()
            if chip_id not in seen:
                seen.add(chip_id)
                found_ids.append(chip_id)

        patterns = (
            r"compare_id:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"(?:probe_spi_rdid|spi_rdid)\s*:\s*id1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
            r"\bid1\s*0x([0-9a-fA-F]+),\s*id2\s*0x([0-9a-fA-F]+)",
        )
        for pat in patterns:
            m_id = re.search(pat, s, re.IGNORECASE)
            if not m_id:
                continue
            try:
                chip_id = f"0x{int(m_id.group(1), 16):02X}{int(m_id.group(2), 16):X}"
            except ValueError:
                continue
            if chip_id not in seen:
                seen.add(chip_id)
                found_ids.append(chip_id)

    if not found_ids:
        return "N/A"
    return ", ".join(found_ids)


def _parse_minipro_device_info(lines: list[str], chip_fallback: str) -> tuple[str, str, str]:
    """Extract (model, vendor, size) from minipro info output."""
    model = chip_fallback or "N/A"
    vendor = "N/A"
    size_str = "N/A"

    for raw in lines:
        s = (raw or "").strip()
        if not s:
            continue

        m_name = re.match(r"^Name:\s*(.+)$", s, re.IGNORECASE)
        if m_name:
            model = m_name.group(1).strip() or model

        m_mfr = re.match(r"^Manufacturer:\s*(.+)$", s, re.IGNORECASE)
        if m_mfr:
            vendor = m_mfr.group(1).strip() or vendor

        if size_str == "N/A":
            m_size = re.match(r"^(?:Memory|Size):\s*(.+)$", s, re.IGNORECASE)
            if m_size:
                size_str = m_size.group(1).strip() or size_str

    if vendor == "N/A" and model and model != "N/A":
        vm = re.match(r"^([A-Za-z]+)", model)
        if vm:
            vendor = vm.group(1)

    return model or "N/A", vendor or "N/A", size_str


def _sha256_file(path: str) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(65536), b""):
            h.update(chunk)
    return h.hexdigest()


def _fmt_elapsed(seconds: float) -> str:
    return f"{seconds:.1f}s"


def _fmt_bytes(size: int) -> str:
    value = float(max(0, int(size)))
    units = ("B", "KiB", "MiB", "GiB", "TiB")
    unit_idx = 0
    while value >= 1024.0 and unit_idx < len(units) - 1:
        value /= 1024.0
        unit_idx += 1
    if unit_idx == 0:
        return f"{int(value)} {units[unit_idx]}"
    return f"{value:.1f} {units[unit_idx]}"


def _fmt_eta(seconds: float) -> str:
    if seconds < 0:
        seconds = 0
    total = int(round(seconds))
    m, s = divmod(total, 60)
    h, m = divmod(m, 60)
    if h:
        return f"ETA {h:d}:{m:02d}:{s:02d}"
    if m:
        return f"ETA {m:d}:{s:02d}"
    return f"ETA {s:d}s"


def _completion_label(rc: int, had_error: bool = False) -> str:
    if rc == 0:
        return "Ok"
    if had_error:
        return "Error"
    return "Fail"


def _system_beep(frequency: int = 1000, duration_ms: int = 200) -> None:
    """Cross-platform beep for operation completion."""
    if winsound:
        try:
            winsound.Beep(frequency, duration_ms)
        except Exception:
            pass
    else:
        # Unix: bell character
        try:
            sys.stdout.write('\a')
            sys.stdout.flush()
        except Exception:
            pass


if _TK_AVAILABLE and ttk is not None:
    class _CollapsibleFrame(ttk.Frame):  # type: ignore[misc]

        def __init__(self, parent: Any, text: str = "", **kwargs) -> None:
            super().__init__(parent, **kwargs)
            self.expanded = False

            # Header with toggle button
            header = ttk.Frame(self)
            header.pack(fill="x", padx=0, pady=0)

            self.toggle_btn = ttk.Button(header, text="▶", width=2, command=self.toggle)
            self.toggle_btn.pack(side="left", padx=4, pady=4)

            ttk.Label(header, text=text, font=("", 10, "bold")).pack(side="left")

            # Content frame (initially hidden)
            self.container: ttk.Frame = ttk.Frame(self)
            self.container.pack(fill="both", expand=True, padx=12, pady=(0, 8))

        def toggle(self) -> None:
            """Toggle expand/collapse state."""
            if self.expanded:
                self.container.pack_forget()
                self.toggle_btn.config(text="▶")
                self.expanded = False
            else:
                self.container.pack(fill="both", expand=True, padx=12, pady=(0, 8))
                self.toggle_btn.config(text="▼")
            self.expanded = True


# ────────────────────────── GUI helpers ────────────────────────────────────────

class _LogWidget(_ScrolledTextBase):  # type: ignore[misc]
    """Read-only scrolled text widget with colour-coded output."""

    def __init__(
        self,
        parent: tk.Widget,
        line_sink: Callable[[str], None] | None = None,
        **kw: object,
    ) -> None:
        super().__init__(parent, state="disabled", wrap="word",
                         bg="#1e1e1e", fg="#d4d4d4",
                         font=_pick_mono(10), **kw)
        self._line_sink = line_sink
        self.tag_config("err", foreground="#f44747")
        self.tag_config("ok",  foreground="#6a9955")
        self.tag_config("hdr", foreground="#569cd6")
        self.tag_config("cmd", foreground="#c586c0")
        self.tag_config("warn", foreground="#d7ba7d")
        self.tag_config("info", foreground="#9cdcfe")
        self.tag_config("meta", foreground="#4ec9b0")
        self.tag_config("eta", foreground="#ffd166")
        self.tag_config("sha", foreground="#b5cea8")
        self.tag_config("done", foreground="#89d185")

    def set_palette(self, dark: bool) -> None:
        if dark:
            self.configure(bg="#1e1e1e", fg="#d4d4d4", insertbackground="#d4d4d4")
            self.tag_config("err", foreground="#ff6b6b")
            self.tag_config("ok", foreground="#7fd18b")
            self.tag_config("hdr", foreground="#7fb3ff")
            self.tag_config("cmd", foreground="#d7aefb")
            self.tag_config("warn", foreground="#f2cc8f")
            self.tag_config("info", foreground="#8bd3ff")
            self.tag_config("meta", foreground="#5dd6c3")
            self.tag_config("eta", foreground="#ffd166")
            self.tag_config("sha", foreground="#c5e1a5")
            self.tag_config("done", foreground="#9ae6b4")
        else:
            self.configure(bg="#ffffff", fg="#1f2937", insertbackground="#111827")
            self.tag_config("err", foreground="#b91c1c")
            self.tag_config("ok", foreground="#15803d")
            self.tag_config("hdr", foreground="#1d4ed8")
            self.tag_config("cmd", foreground="#7c3aed")
            self.tag_config("warn", foreground="#b45309")
            self.tag_config("info", foreground="#0369a1")
            self.tag_config("meta", foreground="#0f766e")
            self.tag_config("eta", foreground="#a16207")
            self.tag_config("sha", foreground="#166534")
            self.tag_config("done", foreground="#047857")

    def append(self, text: str) -> None:
        self.config(state="normal")
        tag = ""
        lo = text.lower()
        if text.startswith("$ "):
            tag = "cmd"
        elif lo.startswith("warning") or "warning:" in lo or "warn:" in lo:
            tag = "warn"
        elif lo.startswith("error") or "error:" in lo or "failed" in lo or "abort" in lo:
            tag = "err"
        elif lo.startswith("sha256sum:"):
            tag = "sha"
        elif lo.startswith("timetaken:") or lo.startswith("eta:"):
            tag = "eta"
        elif lo.startswith("completed:"):
            tag = "done"
        elif lo.startswith("progress") or "%" in text:
            tag = "meta"
        elif any(k in lo for k in ("done", "success", "verified", "complete")):
            tag = "ok"
        elif any(k in lo for k in ("found", "using", "select", "setting", "saved", "loaded")):
            tag = "info"
        self.insert("end", text + "\n", tag)
        self.see("end")
        self.config(state="disabled")
        if self._line_sink is not None:
            try:
                self._line_sink(text)
            except Exception:
                pass

    def clear(self) -> None:
        self.config(state="normal")
        self.delete("1.0", "end")
        self.config(state="disabled")


class _ProgressFrame(_TtkFrameBase):  # type: ignore[misc]

    def __init__(self, parent: tk.Widget, length: int = 300) -> None:
        super().__init__(parent)
        self._pct_var = tk.StringVar(value="")
        self._eta_var = tk.StringVar(value="")
        self._started_at: datetime | None = None
        self._last_eta_pct: int = 0
        self._bar = ttk.Progressbar(self, length=length, maximum=100)
        self._bar.pack(side="left", fill="x", expand=True)
        ttk.Label(self, textvariable=self._pct_var, width=5, anchor="e").pack(side="left", padx=(4, 0))
        ttk.Label(self, textvariable=self._eta_var, width=12, anchor="w").pack(side="left", padx=(6, 0))

    def begin(self) -> None:
        self._started_at = datetime.now()
        self._last_eta_pct = 0
        self._eta_var.set("ETA --")

    def pulse_start(self) -> None:
        self.begin()
        self._bar.config(mode="indeterminate")
        self._bar.start(10)
        self._pct_var.set("…")

    def stop_reset(self) -> None:
        self._bar.stop()
        self._bar.config(mode="determinate", value=0)
        self._pct_var.set("")
        self._eta_var.set("")
        self._started_at = None
        self._last_eta_pct = 0

    def set_percent(self, pct: int) -> None:
        self._bar.config(mode="determinate", value=pct)
        self._pct_var.set(f"{pct}%")
        # Recalculate ETA only every 10% to reduce overhead
        should_update_eta = (pct - self._last_eta_pct >= 10) or (pct < 10 and self._last_eta_pct > 0) or pct >= 100
        if self._started_at is not None and 0 < pct < 100 and should_update_eta:
            elapsed = (datetime.now() - self._started_at).total_seconds()
            eta = elapsed * (100 - pct) / max(pct, 1)
            self._eta_var.set(_fmt_eta(eta))
            self._last_eta_pct = pct
        elif pct >= 100:
            self._eta_var.set("ETA 0s")
            self._last_eta_pct = 100
        elif pct < 10 and self._last_eta_pct == 0:
            self._eta_var.set("ETA --")


# ────────────────────────── shared autodetect mixin ───────────────────────────

class _ChipMixin:
    """Shared chip auto-detect wiring for Read / Write / Info pages."""

    # Declared so Pylance knows the types; concrete subclasses set these in __init__
    root: tk.Tk
    state: AppState
    log: _LogWidget
    chip_var: tk.StringVar
    chip_combo: ttk.Combobox
    progress: _ProgressFrame

    def _autodetect(self) -> None:
        if _is_minipro_tool(self.state.tool, self.state.binary):
            self.log.append("minipro mode: autodetecting SPI chip via -a 8 (fallback -a 16, then supported parts)…")
            self.progress.pulse_start()

            def _worker_minipro() -> None:
                detected, label, chips, lines, bus = _autodetect_minipro_spi_devices(self.state.binary)
                for ln in lines[:60]:
                    _safe_after(self.root, 0, lambda l=ln: self.log.append(l))
                if detected:
                    self.state.programmer = _MINIPRO_PROGRAMMER_ARG
                    if label:
                        _PROGRAMMER_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = label
                hint = None
                if not chips:
                    hint = "No SPI devices matched via minipro -a 8/-a 16; showing supported minipro parts instead."
                elif bus:
                    _safe_after(self.root, 0, lambda b=bus: self.log.append(f"Autodetect matched {len(chips)} device(s) on SPI{b}."))
                _safe_after(self.root, 0, lambda: self._autodetect_done(chips, self.state.programmer or None, hint))

            threading.Thread(target=_worker_minipro, daemon=False).start()
            return

        if not self.state.programmer:
            self.log.append("Select a programmer first.")
            return
        self.log.append("Detecting ROM…")
        self.progress.pulse_start()
        q: queue.Queue[str] = queue.Queue()
        log_ref = self.log
        root_ref = self.root

        def _drain() -> None:
            try:
                while True:
                    log_ref.append(q.get_nowait())
            except queue.Empty:
                pass

        def _worker() -> None:
            chips, suggested, _probe_ids, failure_hint = _detect_chips(
                self.state.binary,
                self.state.programmer,
                q,
                use_sudo=self.state.use_sudo,
                sudo_password=self.state.sudo_password,
            )
            _safe_after(root_ref, 0, _drain)
            _safe_after(root_ref, 0, lambda: self._autodetect_done(chips, suggested, failure_hint))

        threading.Thread(target=_worker, daemon=False).start()

    def _autodetect_done(
        self,
        chips: list[str],
        suggested: str | None = None,
        failure_hint: str | None = None,
    ) -> None:
        self.progress.stop_reset()
        self.chip_combo["values"] = chips
        if chips:
            self.chip_var.set(chips[0])
            self.log.append(f"Found {len(chips)} chip(s): {', '.join(chips)}")
            if len(chips) > 1:
                self.log.append("WARNING: Multiple chips detected — select the correct one.")
        else:
            if failure_hint:
                self.log.append(f"ERROR: {failure_hint}")
            self.log.append("No chip detected. Check programmer connection.")
            if suggested and suggested != self.state.programmer:
                self.log.append(
                    f"HINT: flashrom suggests programmer: {suggested}\n"
                    f"      Update the Programmer field and try again."
                )


# ────────────────────────── pages ─────────────────────────────────────────────

class PageRead(_ChipMixin):
    _last_save_dir: str | None = None  # persists across Detect ROM calls

    def __init__(self, nb: ttk.Notebook, state: "AppState", log: _LogWidget, root: tk.Tk, app: "FlashGUI | None" = None) -> None:
        self.state = state
        self.log = log
        self.root = root
        self.app = app

        self.frame = ttk.Frame(nb)
