# Theme aliases for compatibility with ttkbootstrap/legacy configs
_THEME_ALIASES: dict[str, str] = {
    "darkly": "calm-dark",
    "cyborg": "dark-carbon",
    "superhero": "dark-midnight",
    "vapor": "dark-graphite",
    "solar": "calm-dark",
    "flatly": "minimal-light",
    "morph": "minimal-light",
}


def _resolve_theme_name(available_themes: list[str], requested: str) -> str:
    """Resolve user-selected theme to an actually available theme name.
    
    Handles both direct theme names and aliases. If requested theme is not
    available, checks aliases. Returns empty string if no match found.
    """
    req = (requested or "").strip()
    if not req:
        return ""
    
    available_set = set(available_themes)
    
    # Check if exact match exists
    if req in available_set:
        return req
    
    # Check aliases
    mapped = _THEME_ALIASES.get(req.lower(), "")
    if mapped and mapped in available_set:
        return mapped
    
    return ""

