# ── Qt6 XCB crash workaround ──────────────────────────────────────────────────
# On Linux systems without XRandR ≥ 1.2 (VMs, containers, some Kali setups)
# Qt6's XCB platform plugin crashes with "free(): invalid pointer" or segfault
# during QApplication initialisation.  These env vars must be set BEFORE
# QApplication is constructed (setting them here at import time is fine).
if sys.platform.startswith("linux"):
    os.environ.setdefault("LANG", "C.UTF-8")                # force UTF-8 locale (avoids xkbcommon parsing errors on VMs)
    os.environ.setdefault("LC_ALL", "C.UTF-8")              # force all locale categories to UTF-8
    os.environ.setdefault("QT_XCB_NO_MITSHM", "1")          # no SHM in VMs
    os.environ.setdefault("QT_XCB_NO_XI2", "1")             # no XI2 on old X servers
    os.environ.setdefault("QT_AUTO_SCREEN_SCALE_FACTOR", "0") # skip XRandR DPI
    os.environ.setdefault("QT_SCREEN_SCALE_FACTORS", "1")     # force 1× scale
    os.environ.setdefault("QT_ENABLE_HIGHDPI_SCALING", "0")   # Qt6 HiDPI off
    os.environ.setdefault("QT_XCB_GL_INTEGRATION", "none")    # no GL in XCB
    os.environ.setdefault("LIBGL_ALWAYS_SOFTWARE", "1")       # SW render fallback
    os.environ.setdefault("QT_FORCE_SOFTWARE_OPENGL", "1")    # force software OpenGL
    os.environ.setdefault("QT_XCB_FORCE_SOFTWARE_RASTERIZER", "1")  # disable HW rasterizer
    os.environ.setdefault("QT_RHI_BACKEND", "software")       # force RHI to use software backend only
    os.environ.setdefault("QT_STYLE_OVERRIDE", "Fusion")      # use Fusion style (minimal, no HW accel)
    os.environ.setdefault("QT_SVG_RASTERIZER", "native")      # use native SVG rasterizer
    os.environ.setdefault("IBUS_ENABLE_SYNC_MODE", "1")       # IBus sync mode
    os.environ.setdefault("QT_IM_MODULE", "compose")          # use compose input method (avoids XKB issues)
    os.environ.setdefault("XKBCOMMON_NO_COMPOSE", "1")        # disable XKbCommon compose file parsing (avoids corrupt locale errors)
    # Suppress all graphics/X11/QML warnings to keep console clean on VMs
    os.environ.setdefault("QT_LOGGING_RULES", 
        "qt.qpa.*=false;qt.xkb.*=false;qt.qml.*=false;qt.xrender.*=false;qt.rhi.*=false;qt.opengl.*=false;qt.svg.*=false;qt.gui.*=false")

faulthandler.enable(all_threads=True)

