def _effective_use_native_file_dialogs(use_native_dialogs: bool) -> bool:
    """Return effective native-dialog usage for Qt file pickers.

    KDE/Plasma sessions default to Qt's non-native dialog for better
    stability across desktop/session variations.
    """
    return bool(use_native_dialogs) and not _is_kde_desktop()


def _can_use_kdialog(use_native_dialogs: bool) -> bool:
    """Return whether KDE native picker integration should be attempted."""
    return (
        bool(use_native_dialogs)
        and sys.platform.startswith("linux")
        and _is_kde_desktop()
        and shutil.which("kdialog") is not None
    )


def _qt_filter_to_kdialog_filter(file_filter: str) -> str:
    """Convert Qt filter syntax to kdialog filter syntax."""
    parts: list[str] = []
    for item in (file_filter or "").split(";;"):
        entry = item.strip()
        if not entry:
            continue
        if "(" in entry and ")" in entry:
            name, pattern = entry.rsplit("(", 1)
            parts.append(f"{pattern.rstrip(')')}|{name.strip()}")
        else:
            parts.append(entry)
    return "\n".join(parts) if parts else "*|All Files"


def _run_kdialog(cmd: list[str]) -> tuple[str, bool, bool]:
    """Run kdialog. Returns (path, handled, canceled)."""
    try:
        proc = subprocess.run(
            cmd,
            check=False,
            capture_output=True,
            text=True,
            errors="replace",
            timeout=30,
        )
    except Exception:
        # Runtime/invocation problem -> caller should fall back to Qt dialog.
        return "", False, False

    if proc.returncode != 0:
        # User cancel (or tool-level rejection): do not open a second dialog.
        return "", True, True

    path = (proc.stdout or "").strip()
    return path, True, False


def _kde_get_open_file_name(title: str, start_dir: str, file_filter: str) -> tuple[str, bool, bool]:
    return _run_kdialog([
        "kdialog",
        "--title",
        title,
        "--getopenfilename",
        start_dir,
        _qt_filter_to_kdialog_filter(file_filter),
    ])


def _kde_get_save_file_name(title: str, start_path: str, file_filter: str) -> tuple[str, bool, bool]:
    return _run_kdialog([
        "kdialog",
        "--title",
        title,
        "--getsavefilename",
        start_path,
        _qt_filter_to_kdialog_filter(file_filter),
    ])


def _kde_get_existing_directory(title: str, start_dir: str) -> tuple[str, bool, bool]:
    return _run_kdialog([
        "kdialog",
        "--title",
        title,
        "--getexistingdirectory",
        start_dir,
    ])


def _qfiledialog_options(use_native_dialogs: bool) -> QFileDialog.Option:
    opts = QFileDialog.Option(0)
    if not _effective_use_native_file_dialogs(use_native_dialogs):
        opts |= QFileDialog.Option.DontUseNativeDialog
    return opts


def _qt_get_open_file_name(
    parent: QWidget,
    title: str,
    start_dir: str,
    file_filter: str,
    *,
    use_native_dialogs: bool,
) -> tuple[str, bool]:
    if _can_use_kdialog(use_native_dialogs):
        kpath, handled, canceled = _kde_get_open_file_name(title, start_dir, file_filter)
        if handled:
            return (kpath, bool(kpath)) if not canceled else ("", False)

    path, selected_filter = QFileDialog.getOpenFileName(
        parent,
        title,
        start_dir,
        file_filter,
        options=_qfiledialog_options(use_native_dialogs),
    )
    return path, bool(path or selected_filter)


def _qt_get_save_file_name(
    parent: QWidget,
    title: str,
    start_path: str,
    file_filter: str,
    *,
    use_native_dialogs: bool,
) -> tuple[str, bool]:
    if _can_use_kdialog(use_native_dialogs):
        kpath, handled, canceled = _kde_get_save_file_name(title, start_path, file_filter)
        if handled:
            return (kpath, bool(kpath)) if not canceled else ("", False)

    path, selected_filter = QFileDialog.getSaveFileName(
        parent,
        title,
        start_path,
        file_filter,
        options=_qfiledialog_options(use_native_dialogs),
    )
    return path, bool(path or selected_filter)


def _qt_get_existing_directory(
    parent: QWidget,
    title: str,
    start_dir: str,
    *,
    use_native_dialogs: bool,
) -> str:
    if _can_use_kdialog(use_native_dialogs):
        kpath, handled, canceled = _kde_get_existing_directory(title, start_dir)
        if handled:
            return "" if canceled else kpath

    return QFileDialog.getExistingDirectory(
        parent,
        title,
        start_dir,
        options=_qfiledialog_options(use_native_dialogs),
    )


def _qt_preferred_mono_family() -> str:
    """Return the best available fixed-pitch Qt font family for this host."""
    preferred: list[str] = []
    if sys.platform.startswith("win"):
        preferred = ["Consolas", "Cascadia Mono", "Lucida Console", "Courier New"]
    elif sys.platform == "darwin":
        preferred = ["SF Mono", "Menlo", "Monaco", "Courier"]
    else:
        preferred = ["JetBrainsMono Nerd Font", "DejaVu Sans Mono", "Noto Sans Mono", "Liberation Mono", "Monospace"]

    try:
        families = [str(f).strip() for f in QFontDatabase.families() if str(f).strip()]
        family_set = {f.casefold(): f for f in families}

        for name in preferred:
            hit = family_set.get(name.casefold())
            if hit:
                return hit

        fixed = [f for f in families if QFontDatabase.isFixedPitch(f)]
        if fixed:
            fixed.sort(key=lambda s: s.casefold())
            return fixed[0]
    except Exception:
        pass

    # Last-resort family names (Qt will substitute if needed).
    return "Consolas" if sys.platform.startswith("win") else "Courier"


# Keep worker objects alive until they emit finished; otherwise Python GC may
# reclaim signal objects while background threads are still emitting, which can
# crash Qt/PySide with native memory errors.
_LIVE_WORKERS: set["Worker"] = set()


def _retain_worker(worker: "Worker") -> None:
    _LIVE_WORKERS.add(worker)

    def _release() -> None:
        _LIVE_WORKERS.discard(worker)

    worker.signals.finished.connect(_release)


class WorkerSignals(QObject):
    line = Signal(str)
    progress = Signal(int)
    done = Signal(dict)
    error = Signal(str)
    finished = Signal()


class Worker(QRunnable):
    def __init__(self, target: Callable[[WorkerSignals], None]) -> None:
        super().__init__()
        self.target = target
        self.signals = WorkerSignals()

    def run(self) -> None:
        try:
            self.target(self.signals)
        except Exception as exc:
            self.signals.error.emit(str(exc))
        finally:
            self.signals.finished.emit()


class LogWidget(QTextEdit):
    # Extended port of legacy _LogWidget tag scheme (see flashgui_old.py).
    # Adds extra categories + inline token highlighting (paths, IDs, sizes).
    _DARK_PALETTE: dict[str, str] = {
        "err":   "#ff6b6b",
        "ok":    "#7fd18b",
        "hdr":   "#2d81ff",
        "cmd":   "#d7aefb",
        "warn":  "#f88080",
        "info":  "#dfa425",
        "meta":  "#5dd6c3",
        "eta":   "#aacc2e",
        "sha":   "#2eb3b3",
        "done":  "#9ae6b4",
        # inline accents
        "path":  "#fe9ce5",
        "id":    "#ce9178",
        "chip":  "#47b656",
        "num":   "#7653b8",
        "pct":   "#188b52",
    }
    _LIGHT_PALETTE: dict[str, str] = {
        "err":   "#b91c1c",
        "ok":    "#15803d",
        "hdr":   "#1d4ed8",
        "cmd":   "#7c3aed",
        "warn":  "#b45309",
        "info":  "#0369a1",
        "meta":  "#0f766e",
        "eta":   "#a16207",
        "sha":   "#166534",
        "done":  "#047857",
        # inline accents
        "path":  "#1e40af",
        "id":    "#9a3412",
        "chip":  "#6b4f00",
        "num":   "#3f6212",
        "pct":   "#1d4ed8",
    }
    _BOLD_TAGS: set[str] = {"err", "warn", "done", "cmd", "hdr"}

    # Inline highlight regexes (applied on top of the base line colour).
    _INLINE_PATTERNS: tuple[tuple[str, "re.Pattern[str]"], ...] = (
        ("pct",  re.compile(r"\b\d{1,3}%")),
        ("id",   re.compile(r"\b0x[0-9A-Fa-f]{2,}\b")),
        ("num",  re.compile(r"\b\d+\s?(?:kB|KB|MB|GB|bytes?|B)\b")),
        ("chip", re.compile(r"\b(?:GD|W|MX|EN|SST|AT|IS|PM|XM|XT|FM|BY|GIGADEVICE|WINBOND|MACRONIX|EON|MICRON|SPANSION|ISSI|FUDAN)[0-9A-Z]{3,}\b")),
        ("path", re.compile(r"(?:/[\w.+-]+){2,}|[A-Za-z]:\\[\w.\\+-]+")),
    )

    def __init__(self) -> None:
        super().__init__()
        self.setReadOnly(True)
        self.setMinimumHeight(130)
        self._palette: dict[str, str] = dict(self._DARK_PALETTE)

    def set_palette(self, dark: bool) -> None:
        """Switch dark/light colour table and re-colour existing lines."""
        self._palette = dict(self._DARK_PALETTE if dark else self._LIGHT_PALETTE)
        self._recolor_existing()

    @staticmethod
    def _classify(text: str) -> str:
        """Classify a log line. Order matters — most specific rules first."""
        t = text or ""
        lo = t.lower()

        if not t.strip():
            return ""
        if t.startswith("$ "):
            return "cmd"

        # Errors (high priority)
        if (lo.startswith("error") or "error:" in lo or "failed" in lo
                or "abort" in lo or "traceback" in lo or "fatal" in lo
                or lo.startswith("cannot ") or lo.startswith("could not ")
                or "permission denied" in lo or "no such file" in lo):
            return "err"

        # Warnings — includes "Multiple chips…" style ambiguity prompts
        if (lo.startswith("warning") or "warning:" in lo or "warn:" in lo
                or lo.startswith("multiple ") or "ambiguous" in lo
                or "skipping" in lo or "deprecated" in lo):
            return "warn"

        # Hash / checksum lines
        if lo.startswith("sha256sum:") or lo.startswith("md5:") or lo.startswith("sha1:"):
            return "sha"

        # Timing lines
        if (lo.startswith("timetaken:") or lo.startswith("eta:")
                or lo.startswith("elapsed:") or lo.startswith("duration:")):
            return "eta"

        # Completion summary
        if (lo.startswith("completed:") or lo.startswith("finished:")
                or "operation complete" in lo or lo.endswith(" done.")
                or lo == "done." or lo.startswith("done.")):
            return "done"

        # Section headers / tool banners / phase announcements
        if (lo.startswith("tool:") or lo.startswith("tool version")
                or lo.startswith("flashrom v") or lo.startswith("flashprog v")
                or lo.startswith("reading flash") or lo.startswith("writing flash")
                or lo.startswith("erasing ") or lo.startswith("verifying ")
                or lo.startswith("=== ") or lo.endswith(" ===")
                or lo.startswith("--- ")):
            return "hdr"

        # Progress / percentages
        if lo.startswith("progress") or re.search(r"\b\d{1,3}%", t):
            return "meta"

        # Chip / probe metadata
        if (lo.startswith("detected ") or lo.startswith("resolved ")
                or "chip id" in lo or "compare_id" in lo
                or ("id1 0x" in lo and "id2 0x" in lo)
                or lo.startswith("found ") and ("chip" in lo or "flash" in lo)):
            return "meta"

        # Success-ish
        if any(k in lo for k in (" success", "verified", " complete", "ok.", " ready")):
            return "ok"

        # General info / status
        if (lo.startswith("scanning") or lo.startswith("detecting")
                or lo.startswith("programmer set") or lo.startswith("settings ")
                or any(k in lo for k in ("found:", "found ", "using ", "select",
                                          "setting", "saved", "loaded", "opened",
                                          "started", "connected", "initialized"))):
            return "info"

        return ""

    def _make_format(self, tag: str) -> QTextCharFormat | None:
        if not tag:
            return None
        colour = self._palette.get(tag)
        if not colour:
            return None
        fmt = QTextCharFormat()
        fmt.setForeground(QColor(colour))
        if tag in self._BOLD_TAGS:
            fmt.setFontWeight(700)
        return fmt

    def _inline_spans(self, text: str) -> list[tuple[int, int, str]]:
        """Return non-overlapping (start, end, tag) spans for inline accents."""
        spans: list[tuple[int, int, str]] = []
        taken: list[tuple[int, int]] = []
        for tag, pat in self._INLINE_PATTERNS:
            for m in pat.finditer(text):
                s, e = m.start(), m.end()
                if any(not (e <= ts or s >= te) for ts, te in taken):
                    continue
                taken.append((s, e))
                spans.append((s, e, tag))
        spans.sort(key=lambda x: x[0])
        return spans

    def _insert_line(self, cursor: "QTextCursor", text: str) -> None:
        base_tag = self._classify(text)
        base_fmt = self._make_format(base_tag) or QTextCharFormat()
        spans = self._inline_spans(text)
        if not spans:
            cursor.insertText(text + "\n", base_fmt)
            return
        pos = 0
        for s, e, tag in spans:
            if s > pos:
                cursor.insertText(text[pos:s], base_fmt)
            accent = self._make_format(tag) or base_fmt
            # Inherit boldness from base when present.
            if base_tag in self._BOLD_TAGS:
                accent = QTextCharFormat(accent)
                accent.setFontWeight(700)
            cursor.insertText(text[s:e], accent)
            pos = e
        if pos < len(text):
            cursor.insertText(text[pos:], base_fmt)
        cursor.insertText("\n", base_fmt)

    def append_line(self, text: str) -> None:
        cursor = self.textCursor()
        cursor.movePosition(QTextCursor.MoveOperation.End)
        self._insert_line(cursor, text)
        self.moveCursor(QTextCursor.MoveOperation.End)
        self.ensureCursorVisible()

    def _recolor_existing(self) -> None:
        """Re-apply current palette to all existing lines (theme switch)."""
        plain = self.toPlainText().rstrip("\n")
        if not plain:
            return
        self.clear()
        cursor = self.textCursor()
        for line in plain.split("\n"):
            cursor.movePosition(QTextCursor.MoveOperation.End)
            self._insert_line(cursor, line)
        self.moveCursor(QTextCursor.MoveOperation.End)


class ProgressWidget(QObject):
    """Controller for the progress QProgressBar.

    Not a QWidget — the bar itself is placed directly into the page layout
    so that horizontal geometry matches the sibling Command/HashValue rows
    cell-for-cell. Exposes the same public API as before (pulse_start,
    set_percent, stop_reset) plus :attr:`bar` for layout insertion.
    """

    def __init__(self) -> None:
        super().__init__()
        self.bar = QProgressBar()
        self.bar.setRange(0, 100)
        self.bar.setValue(0)
        self.bar.setTextVisible(True)
        self.bar.setFormat("%p%")
        # Match the height of the Command preview box (24 px) for visual parity.
        self.bar.setMaximumHeight(24)
        self.bar.setMinimumHeight(24)
        # Keep native/themed rendering; custom stylesheet here can break
        # dark-theme colors on some styles (e.g. progress turns white).
        self.bar.setStyleSheet("")
        self.percent_label = QLabel("")
        self.eta_label = QLabel("")

        self._pulse_timer = QTimer(self)
        self._pulse_timer.timeout.connect(self._pulse)
        self._pulse_val = 0
        self._start_monotonic = 0.0
        self._last_pct = 0

    def pulse_start(self) -> None:
        self._start_monotonic = time.monotonic()
        self._last_pct = 0
        self._pulse_val = 0
        self.bar.setRange(0, 0)
        self.bar.setFormat("Working...")
        self.percent_label.setText("")
        self.eta_label.setText("")
        self.bar.setToolTip("")
        self._pulse_timer.start(70)

    def _pulse(self) -> None:
        self._pulse_val = (self._pulse_val + 1) % 101

    def set_percent(self, pct: int) -> None:
        if self.bar.maximum() == 0:
            self.bar.setRange(0, 100)
        self.bar.setFormat("%p%")
        pct = max(0, min(100, int(pct)))
        self._last_pct = pct
        self.bar.setValue(pct)
        self.percent_label.setText(f"{pct}%")
        elapsed = max(time.monotonic() - self._start_monotonic, 0.001)
        if pct > 0 and pct < 100:
            remain = elapsed * (100 - pct) / pct
            self.eta_label.setText(_fmt_eta(remain))
            self.bar.setToolTip(f"ETA: {_fmt_eta(remain)}")
        else:
            self.eta_label.setText("")
            self.bar.setToolTip("")

    def stop_reset(self) -> None:
        self._pulse_timer.stop()
        self.bar.setRange(0, 100)
        self.bar.setValue(0)
        self.bar.setFormat("%p%")
        self.percent_label.setText("")
        self.eta_label.setText("")
        self.bar.setToolTip("")


class PageBase(QWidget):
    title = ""

    def __init__(self, app: "FlashGUIQt") -> None:
        super().__init__()
        self.app = app
        self.state = app.state
        self.root_window = app

    def log(self, text: str) -> None:
        self.app.log.append_line(text)

    def info(self, title: str, text: str) -> None:
        QMessageBox.information(self, title, text)

    def warn(self, title: str, text: str) -> None:
        QMessageBox.warning(self, title, text)

    def error(self, title: str, text: str) -> None:
        QMessageBox.critical(self, title, text)

    def apply_runtime_font_preferences(self, font: QFont) -> None:
        """Optional hook for pages with explicitly-set fonts."""
        self.setFont(QFont(font))

    def _show_text_dialog(self, title: str, text: str) -> None:
        dlg = QDialog(self)
        dlg.setWindowTitle(title)
        dlg.resize(980, 620)
        lay = QVBoxLayout(dlg)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(8)
        view = QPlainTextEdit()
        view.setReadOnly(True)
        f = QFont("Consolas")
        if f.family() == "":
            f = QFont("Courier New")
        f.setPointSize(10)
        view.setFont(f)
        view.setPlainText(text)
        lay.addWidget(view, 1)

        row = QHBoxLayout()
        row.addStretch(1)
        close_btn = QPushButton("Close")
        close_btn.clicked.connect(dlg.accept)
        row.addWidget(close_btn)
        lay.addLayout(row)
        dlg.exec()

    def _resolve_tool_binary(self, tool_name: str) -> str | None:
        tool = (tool_name or "").strip().lower()
        if tool == "flashrom":
            candidate = (self.state.flashrom_bin or "").strip() or "flashrom"
        elif tool == "flashprog":
            candidate = (self.state.flashprog_bin or "").strip() or "flashprog"
        elif tool == "minipro":
            candidate = (getattr(self.state, "minipro_bin", "") or "").strip() or "minipro"
        elif tool == "fwinfo":
            candidate = (getattr(self.state, "fwinfo_bin", "") or "").strip() or "fwinfo"
        else:
            candidate = tool_name
        found = shutil.which(candidate) or (candidate if os.path.isfile(candidate) else "")
        if not found:
            self.warn("Binary not found", f"Could not find '{tool_name}'.\n\nSet the binary path in Settings first.")
            return None
        return found

    def _run_capture_to_dialog(
        self,
        title: str,
        cmd: list[str],
        *,
        timeout: int = 90,
        cwd: str | None = None,
        env: dict[str, str] | None = None,
        display_cmd: str | None = None,
        filter_pattern: str | None = None,
    ) -> None:
        pretty = display_cmd or " ".join(cmd)
        self.log(f"$ {pretty}")

        dlg = QDialog(self)
        dlg.setWindowTitle(title)
        dlg.resize(980, 620)
        lay = QVBoxLayout(dlg)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(8)

        view = QPlainTextEdit()
        view.setReadOnly(True)
        f = QFont("Consolas")
        if f.family() == "":
            f = QFont("Courier New")
        f.setPointSize(10)
        view.setFont(f)
        view.setPlainText(f"Running command...\n\n$ {pretty}\n")
        lay.addWidget(view, 1)

        row = QHBoxLayout()
        row.addStretch(1)
        close_btn = QPushButton("Close")
        close_btn.setEnabled(False)
        close_btn.clicked.connect(dlg.accept)
        row.addWidget(close_btn)
        lay.addLayout(row)

        def worker(signals: WorkerSignals) -> None:
            try:
                proc = subprocess.run(
                    cmd,
                    check=False,
                    capture_output=True,
                    text=True,
                    errors="replace",
                    timeout=timeout,
                    cwd=cwd or self.state.workspace_dir,
                    env=env,
                )
                out = ((proc.stdout or "") + ("\n" if proc.stdout and proc.stderr else "") + (proc.stderr or "")).strip()
                if filter_pattern:
                    rx = re.compile(filter_pattern, re.IGNORECASE)
                    lines = [ln for ln in out.splitlines() if rx.search(ln)]
                    out = "\n".join(lines).strip() if lines else f"(no matches for pattern: {filter_pattern})"
                signals.done.emit({"rc": proc.returncode, "output": out})
            except subprocess.TimeoutExpired as exc:
                out_stdout = exc.stdout
                out_stderr = exc.stderr
                if isinstance(out_stdout, bytes):
                    out_stdout = out_stdout.decode("utf-8", errors="replace")
                if isinstance(out_stderr, bytes):
                    out_stderr = out_stderr.decode("utf-8", errors="replace")
                partial = (str(out_stdout or "") + "\n" + str(out_stderr or "")).strip()
                signals.done.emit({
                    "rc": 124,
                    "output": (partial + "\n\nTimed out.").strip(),
                })

        w = Worker(worker)

        def done(payload: dict) -> None:
            rc = int(payload.get("rc", 1))
            out = str(payload.get("output", "")).strip()
            text = f"$ {pretty}\n\nExit code: {rc}\n"
            if out:
                text += "\n" + out
            else:
                text += "\n(no output)"
            view.setPlainText(text)
            close_btn.setEnabled(True)
            self.log(f"{title}: exit {rc}")

        w.signals.done.connect(done)
        w.signals.error.connect(lambda e: view.setPlainText(f"$ {pretty}\n\nERROR: {e}"))
        w.signals.finished.connect(lambda: close_btn.setEnabled(True))
        _retain_worker(w)
        self.app.thread_pool.start(w)
        dlg.exec()

    def _open_resolved_datasheet(self, chip: str, probe_ids: list[tuple[int, int]] | None) -> bool:
        target, downloaded = _resolve_datasheet_target_for_open(chip, probe_ids)
        if not target:
            self.log("ERROR: No datasheet target could be resolved.")
            return False
        _open_datasheet_target(target)
        if downloaded:
            self.log(f"Downloaded datasheet PDF to local cache: {target}")
        self.log(f"Opened datasheet target for {chip}: {target}")
        return True

    def _open_datasheet_candidates(self, candidates: list[str], probe_ids: list[tuple[int, int]] | None) -> None:
        seen_candidates: set[str] = set()
        seen_targets: set[str] = set()
        opened = 0
        for candidate in candidates:
            key = _normalize_chip_key(candidate)
            if not key or key in seen_candidates:
                continue
            seen_candidates.add(key)
            target, downloaded = _resolve_datasheet_target_for_open(candidate, probe_ids)
            if not target or target in seen_targets:
                continue
            seen_targets.add(target)
            _open_datasheet_target(target)
            if downloaded:
                self.log(f"Downloaded datasheet PDF to local cache: {target}")
            self.log(f"Opened datasheet target for {candidate}: {target}")
            opened += 1
        if not opened:
            self.log("ERROR: No datasheet target could be resolved for any candidate.")


class CollapsibleQGroupBox(QGroupBox):
    """Collapsible QGroupBox with ▶/▼ toggle button in the title."""

    def __init__(self, title: str = "", parent: QWidget | None = None) -> None:
        super().__init__(title, parent)
        self.expanded = True
        self._container = QWidget()
        self._container_layout = QVBoxLayout(self._container)
        self._container_layout.setContentsMargins(0, 0, 0, 0)
        
        main_lay = QVBoxLayout(self)
        main_lay.setContentsMargins(0, 0, 0, 0)
        main_lay.addWidget(self._container)
        
        # Customize title with toggle button
        self._setup_toggle()

    def _setup_toggle(self) -> None:
        """Create toggle button in title bar."""
        title = self.title()
        if not title.startswith("▼"):
            self.setTitle(f"▼ {title}")

    def add_widget(self, widget: QWidget) -> None:
        """Add a widget to the collapsible container."""
        self._container_layout.addWidget(widget)

    def add_layout(self, layout: QLayout) -> None:
        """Add a layout to the collapsible container."""
        self._container_layout.addLayout(layout)

    def toggle_collapse(self) -> None:
        """Toggle between expanded and collapsed states."""
        self.expanded = not self.expanded
        title = self.title().lstrip("▶▼ ").strip()
        indicator = "▼" if self.expanded else "▶"
        self.setTitle(f"{indicator} {title}")
        self._container.setVisible(self.expanded)

    def mousePressEvent(self, event: Any) -> None:
        """Toggle collapse on title click."""
        # Only toggle if clicking on the title area (top-left where ▶/▼ is)
        if event.pos().y() < 25 and event.pos().x() < 150:
            self.toggle_collapse()
        else:
            super().mousePressEvent(event)


class OpPageBase(PageBase):
    def __init__(self, app: "FlashGUIQt") -> None:
        super().__init__(app)
        self._build_ui_base()

    def _build_ui_base(self) -> None:
        outer = QVBoxLayout(self)
        outer.setContentsMargins(0, 0, 0, 0)
        outer.setSpacing(6)

        self.form_group = QGroupBox("Controls")
        self.form_group.setObjectName("formGroup")
        self.form_lay = QFormLayout(self.form_group)
        self.form_lay.setContentsMargins(8, 8, 8, 8)
        self.form_lay.setSpacing(4)
        self.form_lay.setRowWrapPolicy(QFormLayout.RowWrapPolicy.DontWrapRows)
        self.form_lay.setFieldGrowthPolicy(QFormLayout.FieldGrowthPolicy.ExpandingFieldsGrow)
        self.form_lay.setFormAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignTop)
        self.form_lay.setLabelAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
        outer.addWidget(self.form_group, 0)

        # Row order: HashValue → Command → Progress.
        # All three rows share a single QGridLayout so the caption column
        # (col 0) and the field column (cols 1..5) line up cell-for-cell —
        # this guarantees identical right edges for Command and Progress.
        grid = QGridLayout()
        grid.setContentsMargins(0, 0, 0, 0)
        grid.setHorizontalSpacing(8)
        grid.setVerticalSpacing(24)
        grid.setColumnStretch(1, 1)  # main field column expands

        def _caption(text: str) -> QLabel:
            lbl = QLabel(text)
            lbl.setFixedWidth(84)
            lbl.setAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
            return lbl

        # Row 0 — HashValue : [sha]   Time: [elapsed]  Completed: [completed]
        self.sha = QLineEdit("—")
        self.sha.setReadOnly(True)
        self.sha.setMaximumHeight(24)
        self.elapsed = QLabel("—")
        self.completed = QLabel("—")
        grid.addWidget(_caption("HashValue :"), 0, 0)
        grid.addWidget(self.sha,                0, 1)
        grid.addWidget(QLabel("Time:"),         0, 2)
        grid.addWidget(self.elapsed,            0, 3)
        grid.addWidget(QLabel("Completed:"),    0, 4)
        grid.addWidget(self.completed,          0, 5)

        # Row 1 — Command : [cmd_preview spanning cols 1..5]
        self.cmd_preview = QLineEdit("")
        self.cmd_preview.setReadOnly(False)
        self.cmd_preview.setPlaceholderText("—")
        self.cmd_preview.setMinimumHeight(24)
        self.cmd_preview.setMaximumHeight(24)
        self._command_user_edited = False
        self.cmd_preview.textEdited.connect(self._on_command_preview_text_edited)
        grid.addWidget(_caption("Commands :"), 1, 0)
        grid.addWidget(self.cmd_preview,      1, 1, 1, 5)

        # Row 2 — Progress : [bar spanning cols 1..5]
        self.progress = ProgressWidget()
        grid.addWidget(_caption("Progress % :"), 2, 0)
        grid.addWidget(self.progress.bar,      2, 1, 1, 5)

        outer.addLayout(grid, 0)
        outer.addStretch(1)

    def apply_runtime_font_preferences(self, font: QFont) -> None:
        cmd_font = QFont(font)
        cmd_font.setPointSize(max(8, int(font.pointSize() or 10)))
        self.cmd_preview.setFont(cmd_font)

    def append_output(self, line: str) -> None:
        self.log(line)

    def _on_command_preview_text_edited(self, _text: str) -> None:
        self._command_user_edited = True

    def set_command_preview(self, cmd: list[str], *, force: bool = False) -> None:
        if self._command_user_edited and not force:
            return
        self.cmd_preview.setText(" ".join(cmd))
        self._command_user_edited = False

    def clear_command_preview(self, *, force: bool = False) -> None:
        if self._command_user_edited and not force:
            return
        self.cmd_preview.clear()
        self._command_user_edited = False

    def _parse_command_preview(self) -> list[str] | None:
        raw = self.cmd_preview.text().strip()
        if not raw:
            return None
        try:
            parsed = shlex.split(raw, posix=not sys.platform.startswith("win"))
        except ValueError as exc:
            self.log(f"WARNING: Invalid command syntax in Commands field: {exc}. Using generated command.")
            return None
        return parsed or None

    def get_effective_command(self, default_cmd: list[str]) -> tuple[list[str], bool]:
        parsed = self._parse_command_preview() if self._command_user_edited else None
        if parsed:
            return parsed, True
        return self.state.with_verbose(default_cmd), False

    @staticmethod
    def _arg_after(cmd: list[str], *flags: str) -> str | None:
        for i, token in enumerate(cmd):
            if token in flags and i + 1 < len(cmd):
                return str(cmd[i + 1]).strip()
        return None

    def _execute_command(
        self,
        cmd: list[str],
        started: datetime,
        on_done: Callable[[int, float, bool], None],
        use_progress: bool = True,
        apply_verbose: bool = True,
    ) -> None:
        cmd = self.state.with_verbose(cmd) if apply_verbose else list(cmd)
        run_cmd, _ = _with_optional_sudo_for_internal(
            cmd,
            use_sudo=self.state.use_sudo,
            sudo_password=self.state.sudo_password,
        )
        self.append_output(f"$ {' '.join(run_cmd)}")
        self.set_command_preview(run_cmd)
        self.progress.stop_reset()
        if use_progress:
            self.progress.pulse_start()
        self.sha.setText("—")
        self.elapsed.setText("—")
        self.completed.setText("—")

        q: queue.Queue[str] = queue.Queue()
        had_error = {"v": False}

        def worker(signals: WorkerSignals) -> None:
            stop_evt = threading.Event()

            def drain() -> None:
                while not stop_evt.is_set() or not q.empty():
                    try:
                        line = q.get(timeout=0.08)
                    except queue.Empty:
                        continue
                    signals.line.emit(line)

            t = threading.Thread(target=drain, daemon=True)
            t.start()
            try:
                if use_progress:
                    rc = _run_command_progress(
                        cmd,
                        q,
                        pct_callback=lambda p: signals.progress.emit(int(p)),
                        use_sudo=self.state.use_sudo,
                        sudo_password=self.state.sudo_password,
                        echo_command=False,
                    )
                else:
                    rc = _run_command(
                        cmd,
                        q,
                        use_sudo=self.state.use_sudo,
                        sudo_password=self.state.sudo_password,
                        echo_command=False,
                    )
            finally:
                stop_evt.set()
                t.join(timeout=1.0)

            elapsed = (datetime.now() - started).total_seconds()
            signals.done.emit({"rc": rc, "elapsed": elapsed})

        w = Worker(worker)

        def on_line(line: str) -> None:
            if "error" in line.lower() or "failed" in line.lower():
                had_error["v"] = True
            self.append_output(line)

        def on_progress(pct: int) -> None:
            self.progress.set_percent(pct)

        def finish(payload: dict) -> None:
            rc = int(payload.get("rc", 1))
            elapsed = float(payload.get("elapsed", 0.0))
            if use_progress and rc == 0:
                self.progress.set_percent(100)
            else:
                self.progress.stop_reset()
            self.elapsed.setText(_fmt_elapsed(elapsed))
            on_done(rc, elapsed, had_error["v"])

        w.signals.line.connect(on_line)
        w.signals.progress.connect(on_progress)
        w.signals.done.connect(finish)
        w.signals.error.connect(lambda e: self.log(f"ERROR: {e}"))
        _retain_worker(w)
        self.app.thread_pool.start(w)


class ChipMixin:
    def setup_chip_controls(self, form: QFormLayout, parent: QWidget) -> tuple[QComboBox, QPushButton]:
        chip_combo = QComboBox()
        chip_combo.setEditable(True)
        detect_btn = QPushButton("Detect ROM")
        detect_btn.setMinimumWidth(140)
        row = QWidget(parent)
        lay = QHBoxLayout(row)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.addWidget(chip_combo, 1)
        lay.addWidget(detect_btn)
        form.addRow("Select Chip:", row)

        # Keep the sidebar chip status in sync with manual combo edits/selection.
        app = getattr(self, "app", None)

        def _on_chip_text_changed(text: str) -> None:
            t = (text or "").strip()
            if app is None:
                return
            app.state.selected_chip = t
            status = getattr(app, "chip_status", None)
            if status is not None:
                status.setText(t or "Not detected")
            # Mirror to other pages' chip combos so all pages stay aligned.
            for p in getattr(app, "pages", []) or []:
                other = getattr(p, "chip_combo", None)
                if other is None or other is chip_combo:
                    continue
                if other.currentText().strip() == t:
                    continue
                other.blockSignals(True)
                try:
                    idx = other.findText(t)
                    if idx >= 0:
                        other.setCurrentIndex(idx)
                    else:
                        other.setCurrentText(t)
                finally:
                    other.blockSignals(False)

        chip_combo.currentTextChanged.connect(_on_chip_text_changed)
        return chip_combo, detect_btn

    def autodetect(
        self,
        combo: QComboBox,
        log_fn: Callable[[str], None],
        state: AppState,
        app: "FlashGUIQt",
        prefer_probe_resolution: bool = False,
    ) -> None:
        if _has_active_operations():
            count = _active_operation_count()
            plural = "s" if count != 1 else ""
            log_fn(
                f"INFO: Detect ROM is disabled while {count} active operation{plural} is running. "
                "Wait for completion, then try Detect ROM again."
            )
            try:
                app.statusBar().showMessage("Detect ROM is disabled while an operation is running", 3000)
            except Exception:
                pass
            return

        if _is_minipro_tool(state.tool, state.binary):
            log_fn("minipro mode: autodetecting SPI chip via -a 8 (fallback -a 16, then supported parts)…")

            def done_minipro(payload: dict) -> None:
                raw_chips = payload.get("chips", []) or []
                chips: list[str] = []
                for c in raw_chips:
                    cs = str(c).strip()
                    if cs and cs not in chips:
                        chips.append(cs)
                combo.clear()
                combo.addItems(chips)
                if chips:
                    chosen = chips[0]
                    combo.setCurrentIndex(0)
                    app.sync_chip_selection(chips, chosen)
                    app.chip_status.setText(chosen)
                    log_fn(f"Loaded {len(chips)} minipro part(s). Select the target chip from the dropdown.")
                    if len(chips) > 1:
                        combo.showPopup()
                else:
                    app.chip_status.setText("Not detected")
                    hint = str(payload.get("failure_hint", "") or "").strip()
                    if hint:
                        log_fn(f"ERROR: {hint}")
                    log_fn("No minipro parts detected.")
                    app.sync_chip_selection([], "")

                suggested = str(payload.get("suggested", "") or "").strip()
                if suggested:
                    state.programmer = suggested
                    app.programmer_combo.setCurrentText(state.programmer)
                    log_fn(f"Programmer set to {state.programmer}")

            def worker_minipro(signals: WorkerSignals) -> None:
                detected, label, chips, lines, bus = _autodetect_minipro_spi_devices(state.binary)
                for line in lines[:80]:
                    signals.line.emit(line)
                if detected:
                    state.programmer = _MINIPRO_PROGRAMMER_ARG
                    if label:
                        _PROGRAMMER_LABEL_HINTS[_MINIPRO_PROGRAMMER_ARG] = label
                if chips and bus:
                    signals.line.emit(f"Autodetect matched {len(chips)} device(s) on SPI{bus}.")
                failure_hint = None if chips else "No SPI devices matched via minipro -a 8/-a 16; showing supported minipro parts instead."
                signals.done.emit(
                    {
                        "chips": chips,
                        "suggested": state.programmer if detected else None,
                        "probe_ids": [],
                        "failure_hint": failure_hint,
                    }
                )

            w = Worker(worker_minipro)
            w.signals.line.connect(log_fn)
            w.signals.done.connect(done_minipro)
            w.signals.error.connect(lambda e: log_fn(f"ERROR: detect failed: {e}"))
            _retain_worker(w)
            app.thread_pool.start(w)
            return

        if not state.programmer:
            log_fn("ERROR: Select a programmer first.")
            return

        log_fn("Detecting chip using current programmer...")

        def worker(signals: WorkerSignals) -> None:
            q: queue.Queue[str] = queue.Queue()
            chips, suggested, probe_ids, failure_hint = _detect_chips(
                state.binary,
                state.programmer,
                q,
                use_sudo=state.use_sudo,
                sudo_password=state.sudo_password,
            )
            while not q.empty():
                try:
                    line = q.get_nowait()
                except queue.Empty:
                    break
                signals.line.emit(line)
            signals.done.emit(
                {
                    "chips": chips,
                    "suggested": suggested,
                    "probe_ids": probe_ids,
                    "failure_hint": failure_hint,
                }
            )

        w = Worker(worker)

        def done(payload: dict) -> None:
            raw_chips = payload.get("chips", []) or []
            probe_ids_raw = payload.get("probe_ids", []) or []
            probe_ids: list[tuple[int, int]] = []
            for pid in probe_ids_raw:
                if isinstance(pid, (tuple, list)) and len(pid) == 2:
                    try:
                        probe_ids.append((int(pid[0]), int(pid[1])))
                    except (TypeError, ValueError):
                        continue
            chips: list[str] = []
            for c in raw_chips:
                cs = str(c).strip()
                if cs and cs not in chips:
                    chips.append(cs)
            suggested = payload.get("suggested")
            failure_hint = payload.get("failure_hint")
            combo.clear()
            combo.addItems(chips)
            if chips:
                log_fn(f"Detected chip(s): {', '.join(chips)}")
                chosen = chips[0]
                if prefer_probe_resolution:
                    resolved = _resolve_chip_from_probe(chips, probe_ids)
                    if resolved:
                        chosen = resolved
                        if chosen not in chips:
                            combo.addItem(chosen)
                        log_fn(f"Resolved chip from probe output: {chosen}")
                idx = combo.findText(chosen)
                if idx >= 0:
                    combo.setCurrentIndex(idx)
                else:
                    combo.setCurrentText(chosen)
                app.sync_chip_selection(chips, chosen)
                app.state.last_probe_ids = probe_ids
                app.chip_status.setText(chosen)
                if len(chips) > 1:
                    log_fn("Multiple chips detected — select the correct chip from the dropdown.")
                    combo.showPopup()
            else:
                app.chip_status.setText("Not detected")
                if failure_hint:
                    log_fn(f"ERROR: {failure_hint}")
                log_fn("No chip detected.")
                app.sync_chip_selection([], "")
            if suggested:
                state.programmer = str(suggested)
                app.programmer_combo.setCurrentText(state.programmer)
                log_fn(f"Suggested programmer: {state.programmer}")

        w.signals.done.connect(done)
        w.signals.error.connect(lambda e: log_fn(f"ERROR: detect failed: {e}"))
        _retain_worker(w)
        app.thread_pool.start(w)


class ReadPage(OpPageBase, ChipMixin):
    title = "Read ROM"

    def __init__(self, app: "FlashGUIQt") -> None:
        super().__init__(app)
        self.file_edit = QLineEdit()
        b_browse = QPushButton("Browse")
        b_browse.setMinimumWidth(140)
        row = QWidget(self)
        lay = QHBoxLayout(row)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.addWidget(self.file_edit, 1)
        lay.addWidget(b_browse)
        self.form_lay.addRow("Save ROM to:", row)

        self.chip_combo, b_detect = self.setup_chip_controls(self.form_lay, self)
        self.opt_reveal = QCheckBox("Reveal file upon completion")
        self.opt_nopad = QCheckBox("Remove padding (0xFF) from dump")
        self.form_lay.addRow(self.opt_reveal)
        self.form_lay.addRow(self.opt_nopad)

        self.run_btn = QPushButton("Read ROM")
        self.run_btn.setProperty("kind", "read")
        self.form_lay.addRow(self.run_btn)

        b_browse.clicked.connect(self._browse)
        b_detect.clicked.connect(lambda: self.autodetect(self.chip_combo, self.log, self.state, self.app))
        self.run_btn.clicked.connect(self._run)

        # Auto-populate filename when chip or programmer changes
        self._filename_is_auto = True
        self.chip_combo.currentTextChanged.connect(self._refresh_auto_filename)
        self.app.programmer_combo.currentTextChanged.connect(self._refresh_auto_filename)
        self.file_edit.textEdited.connect(
            lambda text: setattr(self, "_filename_is_auto", not bool(text.strip()))
        )
        self.file_edit.textChanged.connect(lambda _=None: self._refresh_command_preview())
        self.chip_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.programmer_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.tool_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self._refresh_command_preview()

    def _refresh_auto_filename(self) -> None:
        """Auto-populate the save path unless the user has manually entered one."""
        if not self._filename_is_auto:
            return
        chip = self.chip_combo.currentText().strip()
        prog = self.state.programmer.strip()
        if not chip or not prog:
            return
        self.file_edit.setText(_build_rom_filename(self.state.workspace_dir, chip, prog, self.state.tool))

    def _default_cmd(self) -> list[str] | None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp or not chip:
            return None
        if is_minipro:
            return [self.state.binary, "-p", chip, "-r", fp]
        if not self.state.programmer:
            return None
        return [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-r", fp]

    def _refresh_command_preview(self) -> None:
        cmd = self._default_cmd()
        if cmd:
            self.set_command_preview(cmd)
        else:
            self.clear_command_preview()

    def _browse(self) -> None:
        path, ok = _qt_get_save_file_name(
            self,
            "Save ROM dump",
            os.path.expanduser("~"),
            "Binary Files (*.bin);;All Files (*)",
            use_native_dialogs=self.state.use_native_file_dialogs,
        )
        if ok and path:
            self._filename_is_auto = False
            self.file_edit.setText(path)

    def _run(self) -> None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp:
            self.log("ERROR: Select a save path first.")
            return
        if not chip:
            self.log("ERROR: Run Detect ROM to find a chip first.")
            return
        if not is_minipro and not self.state.programmer:
            self.log("ERROR: Select a programmer first.")
            return

        if is_minipro:
            default_cmd = [self.state.binary, "-p", chip, "-r", fp]
            use_progress = True
        else:
            default_cmd = [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-r", fp]
            use_progress = True
        cmd, _ = self.get_effective_command(default_cmd)
        target_fp = self._arg_after(cmd, "-r") or fp
        started = datetime.now()
        do_remove_padding = self.opt_nopad.isChecked()

        def done(rc: int, elapsed: float, had_error: bool) -> None:
            digest = "N/A"
            file_exists = os.path.isfile(target_fp)
            if rc == 0 and file_exists:
                if do_remove_padding:
                    removed = _remove_padding(target_fp)
                    self.log(f"Removed {removed} bytes of 0xFF padding.")
                digest = _sha256_file(target_fp)
                self.sha.setText(digest)
                self.log(f"SHA256SUM: {digest}")
                self.log(f"TimeTaken: {_fmt_elapsed(elapsed)}")
                self.completed.setText("Ok")
                self.log("Completed: Ok")
                if self.opt_reveal.isChecked():
                    self._reveal(target_fp)
                if self.state.beep_on_complete:
                    _system_beep(1000, 200)
            elif not file_exists:
                self.completed.setText("Fail")
                self.log(f"ERROR: ROM was not saved. ({_fmt_elapsed(elapsed)} elapsed)")
                self.log("Completed: Fail")
                if self.state.beep_on_complete:
                    _system_beep(800, 400)
            else:
                status = _completion_label(rc, had_error=had_error)
                self.completed.setText(status)
                self.log(f"Completed: {status}")
                if self.state.beep_on_complete:
                    _system_beep(1000, 200)

        self._execute_command(cmd, started, done, use_progress=use_progress, apply_verbose=False)

    def _reveal(self, path: str) -> None:
        try:
            if sys.platform == "darwin":
                subprocess.Popen(["open", "-R", path])
            elif sys.platform.startswith("linux"):
                subprocess.Popen(["xdg-open", os.path.dirname(path)])
            else:
                subprocess.Popen(["explorer", "/select,", os.path.normpath(path)])
        except Exception as exc:
            self.log(f"WARNING: Could not reveal file in file manager: {exc}")


class WritePage(OpPageBase, ChipMixin):
    title = "Write ROM"

    def __init__(self, app: "FlashGUIQt") -> None:
        super().__init__(app)

        self.file_edit = QLineEdit()
        b_browse = QPushButton("Browse")
        b_browse.setMinimumWidth(140)
        row = QWidget(self)
        lay = QHBoxLayout(row)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.addWidget(self.file_edit, 1)
        lay.addWidget(b_browse)
        self.form_lay.addRow("File to flash:", row)

        self.chip_combo, b_detect = self.setup_chip_controls(self.form_lay, self)

        # Advanced Options in collapsible group
        adv_group = CollapsibleQGroupBox("🔧 Advanced Options")
        adv_lay = QVBoxLayout()
        adv_lay.setContentsMargins(0, 0, 0, 0)
        adv_lay.setSpacing(6)
        self.opt_pad = QCheckBox("Pad file to match chip size")
        self.opt_noverify = QCheckBox("Skip verify after write")
        self.opt_verify_hash_readback = QCheckBox("Verify hash via re-reading ROM")
        adv_lay.addWidget(self.opt_pad)
        adv_lay.addWidget(self.opt_noverify)
        adv_lay.addWidget(self.opt_verify_hash_readback)
        adv_group.add_layout(adv_lay)
        self.form_lay.addRow(adv_group)

        self.run_btn = QPushButton("Write ROM")
        self.run_btn.setProperty("kind", "write")
        self.form_lay.addRow(self.run_btn)

        b_browse.clicked.connect(self._browse)
        b_detect.clicked.connect(lambda: self.autodetect(self.chip_combo, self.log, self.state, self.app))
        self.run_btn.clicked.connect(self._run)
        self.file_edit.textChanged.connect(lambda _=None: self._refresh_command_preview())
        self.chip_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.programmer_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.tool_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.opt_noverify.toggled.connect(lambda _=None: self._refresh_command_preview())
        self._refresh_command_preview()

    def _browse(self) -> None:
        start_dir = (self.state.workspace_dir or "").strip() or os.path.expanduser("~")
        cur = self.file_edit.text().strip()
        if cur:
            cur_dir = os.path.dirname(cur)
            if os.path.isdir(cur_dir):
                start_dir = cur_dir
        if not os.path.isdir(start_dir):
            start_dir = os.path.expanduser("~")
        path, ok = _qt_get_open_file_name(
            self,
            "Select ROM file",
            start_dir,
            "Binary Files (*.bin);;All Files (*)",
            use_native_dialogs=self.state.use_native_file_dialogs,
        )
        if ok and path:
            self.file_edit.setText(path)

    def _default_cmd(self) -> list[str] | None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp or not chip:
            return None
        if is_minipro:
            cmd = [self.state.binary, "-p", chip, "-w", fp]
        else:
            if not self.state.programmer:
                return None
            cmd = [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-w", fp]
            if self.opt_noverify.isChecked():
                cmd.append("-n")
        return cmd

    def _refresh_command_preview(self) -> None:
        cmd = self._default_cmd()
        if cmd:
            self.set_command_preview(cmd)
        else:
            self.clear_command_preview()

    def _run(self) -> None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp or not os.path.isfile(fp):
            self.log("ERROR: Select a valid ROM file.")
            return
        if not chip:
            self.log("ERROR: Run Detect ROM first.")
            return
        if not is_minipro and not self.state.programmer:
            self.log("ERROR: Select a programmer first.")
            return

        chip_size: int | None = None
        if not is_minipro:
            chip_size = _get_chip_size(self.state.binary, self.state.programmer, chip)
            if chip_size:
                file_size = os.path.getsize(fp)
                if file_size > chip_size:
                    self.sha.setText("N/A")
                    self.elapsed.setText(_fmt_elapsed(0.0))
                    self.completed.setText("Fail")
                    self.log("ERROR: Selected image is larger than the detected chip size.")
                    self.log(
                        "ERROR: "
                        f"Image size {_fmt_bytes(file_size)} ({file_size} B) > "
                        f"chip size {_fmt_bytes(chip_size)} ({chip_size} B)."
                    )
                    self.log("Write aborted before flashing. Choose a smaller image or a larger chip.")
                    QMessageBox.warning(
                        self,
                        "Image too large",
                        "Selected image is larger than target chip capacity.\n\n"
                        f"Image: {_fmt_bytes(file_size)} ({file_size} B)\n"
                        f"Chip: {_fmt_bytes(chip_size)} ({chip_size} B)\n\n"
                        "Write was aborted before flashing.",
                    )
                    return

        ans = QMessageBox.question(
            self,
            "Confirm Write",
            "Are you sure you want to write this ROM?\nThis CANNOT be undone.\n\nIt is strongly recommended to back up first!",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No,
        )
        if ans != QMessageBox.StandardButton.Yes:
            return

        actual_fp = fp
        if self.opt_pad.isChecked() and not is_minipro:
            if chip_size:
                actual_fp = _pad_file(fp, chip_size, self.state.tmpdir)
                self.log(f"Padded file to {chip_size} bytes.")
            else:
                self.log("WARNING: Could not determine chip size — skipping padding.")

        if is_minipro:
            default_cmd = [self.state.binary, "-p", chip, "-w", actual_fp]
            use_progress = True
        else:
            default_cmd = [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-w", actual_fp]
            use_progress = True
        if self.opt_noverify.isChecked() and not is_minipro:
            default_cmd.append("-n")

        cmd, user_override = self.get_effective_command(default_cmd)
        if user_override:
            actual_fp = self._arg_after(cmd, "-w") or fp

        started = datetime.now()
        do_verify_hash_readback = self.opt_verify_hash_readback.isChecked()

        def done(rc: int, elapsed: float, had_error: bool) -> None:
            digest = "N/A"
            if os.path.isfile(actual_fp):
                digest = _sha256_file(actual_fp)
                self.sha.setText(digest)
                self.log(f"SHA256SUM: {digest}")
            else:
                self.sha.setText("N/A")
                had_error = True

            if rc == 0 and os.path.isfile(actual_fp) and do_verify_hash_readback and not is_minipro:
                verify_tmp = os.path.join(
                    self.state.tmpdir,
                    f"verify_readback_{int(time.time() * 1000)}.bin",
                )
                verify_cmd = [
                    self.state.binary,
                    "-p",
                    self.state.programmer,
                    "-c",
                    chip,
                    "-r",
                    verify_tmp,
                ]
                self.log("Readback hash verify: reading ROM again for comparison...")
                q_verify: queue.Queue[str] = queue.Queue()
                rc_verify = _run_command(
                    verify_cmd,
                    q_verify,
                    use_sudo=self.state.use_sudo,
                    sudo_password=self.state.sudo_password,
                )
                while not q_verify.empty():
                    line = q_verify.get_nowait()
                    self.log(line)
                    if "error" in line.lower() or "failed" in line.lower():
                        had_error = True

                if rc_verify == 0 and os.path.isfile(verify_tmp):
                    try:
                        readback_digest = _sha256_file(verify_tmp)
                        self.log(f"Readback SHA256SUM: {readback_digest}")
                        if readback_digest == digest:
                            self.log("Readback hash verify: OK (matches source file).")
                        else:
                            had_error = True
                            self.log("ERROR: Readback hash verify FAILED (hash mismatch).")
                    except Exception as exc:
                        had_error = True
                        self.log(f"ERROR: Readback hash verify failed: {exc}")
                else:
                    had_error = True
                    self.log(f"ERROR: Readback command failed (exit {rc_verify}).")

                try:
                    if os.path.isfile(verify_tmp):
                        os.remove(verify_tmp)
                except OSError:
                    pass

            self.log(f"TimeTaken: {_fmt_elapsed(elapsed)}")
            status = _completion_label(rc, had_error=had_error)
            self.completed.setText(status)
            self.log(f"Completed: {status}")
            if rc != 0:
                self.log(f"Write failed (exit {rc}).")
            if self.state.beep_on_complete:
                _system_beep(1000 if rc == 0 else 800, 200)

        self._execute_command(cmd, started, done, use_progress=use_progress, apply_verbose=False)


class VerifyPage(OpPageBase, ChipMixin):
    title = "Verify ROM"

    def __init__(self, app: "FlashGUIQt") -> None:
        super().__init__(app)

        self.file_edit = QLineEdit()
        b_browse = QPushButton("Browse")
        b_browse.setMinimumWidth(140)
        row = QWidget(self)
        lay = QHBoxLayout(row)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.addWidget(self.file_edit, 1)
        lay.addWidget(b_browse)
        self.form_lay.addRow("File to verify against:", row)

        self.chip_combo, b_detect = self.setup_chip_controls(self.form_lay, self)

        # Advanced Options in collapsible group
        adv_group = CollapsibleQGroupBox("🔧 Advanced Options")
        adv_lay = QVBoxLayout()
        adv_lay.setContentsMargins(0, 0, 0, 0)
        adv_lay.setSpacing(6)
        self.opt_ignore_ecc = QCheckBox("Ignore ECC errors (if supported)")
        adv_lay.addWidget(self.opt_ignore_ecc)
        adv_group.add_layout(adv_lay)
        self.form_lay.addRow(adv_group)

        self.run_btn = QPushButton("Verify ROM")
        self.run_btn.setProperty("kind", "verify")
        self.form_lay.addRow(self.run_btn)

        b_browse.clicked.connect(self._browse)
        b_detect.clicked.connect(lambda: self.autodetect(self.chip_combo, self.log, self.state, self.app))
        self.run_btn.clicked.connect(self._run)
        self.file_edit.textChanged.connect(lambda _=None: self._refresh_command_preview())
        self.chip_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.programmer_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self.app.tool_combo.currentTextChanged.connect(lambda _=None: self._refresh_command_preview())
        self._refresh_command_preview()

    def _browse(self) -> None:
        start_dir = (self.state.workspace_dir or "").strip() or os.path.expanduser("~")
        cur = self.file_edit.text().strip()
        if cur:
            cur_dir = os.path.dirname(cur)
            if os.path.isdir(cur_dir):
                start_dir = cur_dir
        if not os.path.isdir(start_dir):
            start_dir = os.path.expanduser("~")
        path, ok = _qt_get_open_file_name(
            self,
            "Select file to verify",
            start_dir,
            "Binary Files (*.bin);;All Files (*)",
            use_native_dialogs=self.state.use_native_file_dialogs,
        )
        if ok and path:
            self.file_edit.setText(path)

    def _default_cmd(self) -> list[str] | None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp or not chip:
            return None
        if is_minipro:
            return [self.state.binary, "-p", chip, "-m", fp]
        if not self.state.programmer:
            return None
        return [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-v", fp]

    def _refresh_command_preview(self) -> None:
        cmd = self._default_cmd()
        if cmd:
            self.set_command_preview(cmd)
        else:
            self.clear_command_preview()

    def _run(self) -> None:
        fp = self.file_edit.text().strip()
        chip = self.chip_combo.currentText().strip()
        is_minipro = _is_minipro_tool(self.state.tool, self.state.binary)
        if not fp or not os.path.isfile(fp):
            self.log("ERROR: Select a valid file.")
            return
        if not chip:
            self.log("ERROR: Run Detect ROM first.")
            return
        if not is_minipro and not self.state.programmer:
            self.log("ERROR: Select a programmer first.")
            return

        if is_minipro:
            default_cmd = [self.state.binary, "-p", chip, "-m", fp]
            use_progress = True
        else:
            default_cmd = [self.state.binary, "-p", self.state.programmer, "-c", chip, "--progress", "-v", fp]
            use_progress = True
        cmd, user_override = self.get_effective_command(default_cmd)
        target_fp = self._arg_after(cmd, "-v", "-m") or fp
        started = datetime.now()

        def done(rc: int, elapsed: float, had_error: bool) -> None:
            digest = _sha256_file(target_fp)
            self.sha.setText(digest)
            self.log(f"SHA256SUM: {digest}")
            self.log(f"TimeTaken: {_fmt_elapsed(elapsed)}")
            status = _completion_label(rc, had_error=had_error)
            self.completed.setText(status)
            self.log(f"Completed: {status}")
            if rc != 0:
                self.log(f"Verify failed (exit {rc}).")
            if self.state.beep_on_complete:
                _system_beep(1000 if rc == 0 else 800, 200)

        self._execute_command(cmd, started, done, use_progress=use_progress, apply_verbose=False)


