        b_copy_log.clicked.connect(lambda: QApplication.clipboard().setText(self.log.toPlainText()))
        b_save_log.clicked.connect(self._save_global_log)
        log_lay.addLayout(log_header)
        log_lay.addWidget(self.log, 1)

        vsplit.addWidget(log_container)
        vsplit.setSizes([700, 250])
        vsplit.setStretchFactor(0, 1)
