        self.pages: list[PageBase] = [
            InfoPage(self),
            ReadPage(self),
            WritePage(self),
            VerifyPage(self),
            ErasePage(self),
            WriteProtectPage(self),
            ToolsPage(self),
            SettingsPage(self),
            HelpAboutPage(self),
        ]

        icon_map = {
            "About ROM": "about-rom",
            "Read ROM": "read-rom",
            "Write ROM": "write-rom",
            "Verify ROM": "verify-rom",
            "Erase ROM": "erase-rom",
            "Write-Protect": "write-protect",
            "Tools": "tools",
            "Help & About": "about-rom",
            "Settings": "settings",
        }
        for p in self.pages:
            self.stack.addWidget(p)
            title = getattr(p, "title", p.__class__.__name__)
            icon_name = icon_map.get(title)
            item = QListWidgetItem(title, self.sidebar)
            if icon_name:
                item.setIcon(_get_icon(icon_name, 20))
            item.setToolTip(title)

        self.sidebar.currentRowChanged.connect(self.stack.setCurrentIndex)
        self.sidebar.setCurrentRow(0)

